window.ASTRO_PATHSHALA_DB = [{"topic":"Sarvashtak Varg से घरों की शक्ति जानें Sarvashtak Varg से सही भविष्यवाणी कैसे करें","text":"नमस्कार एस्ट्रो पाठशाला में आप सभी का\r\nस्वागत है। मित्रों आज मैं आया हूं आपके\r\nसामने प्रेडिक्ट प्रेडिक्शन करने की एक\r\nटेक्निक। जी हां फलादेश\r\nकरने का एक तरीका\r\nयह सर्वाष्टक वर्ग के द्वारा फलादेश करना\r\nयह टेक्निक कुछ आसान है। हमें कुछ\r\nक्लेरिटी देती है। जन्म पत्रिका में हम\r\nसभी जानते हैं कुंडली में 12 भाव होते हैं\r\nऔर नौ ग्रह होते हैं।\r\nजब हम भाव की ताकत निकालना चाहते हैं तो\r\nकई बार भाव का बल निकालते निकालते हमारा\r\nखुद का बल निकल जाता है। मजाक की बात है।\r\nहर भाव\r\nहमें कुछ ना कुछ जीवन से संबंधित चीजों को\r\nदेता है।\r\nपर वो उस चीजों को कितने अच्छे तरह से\r\nहमें डिलीवर करेगा यह उसकी शक्ति पर\r\nनिर्भर करता है। यदि आप ज्योतिष सीखना\r\nचाहते हो तो भाव का बल और ग्रह का बल अगर\r\nयह चीज को समझने की आपके अंदर शक्ति है तो\r\nसमझो आप ज्योतिष भी सीख गए। ज्योतिष को\r\nसमझ जाओगे कि कैसे ज्योतिष का फलादेश किया\r\nजाता है। सर्वाष्टक वर्ग में होता क्या\r\nहै? मैं इधर-उधर की बात ना करते हुए सीधा\r\nआपको एक कुंडली पर लेकर के आना चाहता हूं।\r\nआपके पास भी जो कुंडली है उसको भी खोल\r\nलीजिए और आपके सॉफ्टवेयर में एक टेबल होगी\r\nजिस पे लिखा होता है अष्टक वर्ग टेबल।\r\nउसको आप खोल लीजिए अपने सामने। फिर आपने\r\nक्या करना है? आपकी कुंडली को देखना है और\r\nअपनी कुंडली में देखिएगा जो आपकी कुंडली\r\nका फर्स्ट हाउस है जहां पर लगन लिखा हुआ\r\nहै इंग्लिश में है तो असेंडेंट साइन लिखा\r\nहोगा वहां पर देखिए कितना नंबर है। आपके\r\nसामने यह जो कुंडली है यह मिथुन लग्न की\r\nकुंडली है। क्यों? क्योंकि यह नंबर तीन की\r\nकुंडली है। और अगर आपको यह नंबर तीन क्या\r\nहै? कहां से आया नहीं मालूम तो हमारा\r\nपुराना वीडियो जाकर के देखिएगा।\r\nलग्न बलवान कैसे?\r\nउसमें सारा डिटेल में समझाया है। तो जो\r\nलग्न है वह नंबर तीन है। आपकी कुंडली में\r\nभी एक से लेकर 12 तक कोई ना कोई गिनती\r\nसंख्या लिखी होगी। जो वहां पे लिखा होगा\r\nवही आपका लग्न है। हम इस एग्जांपल कुंडली\r\nकी बात कर रहे हैं। तो यह मिथुन लग्न की\r\nकुंडली है। अब आपने इस टेबल में आना है और\r\nइस टेबल में देखना है कि नंबर तीन कहां\r\nलिखा हुआ है? यह देखिए। नंबर तीन लिखा हुआ\r\nहै। आपको दिखाई दे रहा होगा। नंबर तीन\r\nके नीचे सबसे नीचे देखिए टोटल पॉइंट लिखे\r\nहुए हैं 31।\r\nयह यह समझाने की कोशिश कर रहा है कि हर\r\nग्रह सूर्य, चंद्र, मंगल, बुध, गुरु,\r\nशुक्र, शनि यह सात ग्रह पहले भाव को कितनी\r\nशक्ति प्रदान करते हैं? कितने नंबर देते\r\nहैं? तो टोटल यहां पर हम गिने तो 31 है।\r\nयह बनी बनाई आती है। ज्यादा परेशान होने\r\nकी जरूरत नहीं है। तो आपने यहां पर 31 लिख\r\nदेने हैं। अब देखिए यहां पर हमने\r\n31 नंबर\r\nलिखा हुआ है पहले से ही 31।\r\nयानी कि पहले भाव में 31 नंबर हैं।\r\nअब इसी प्रकार से\r\nनंबर चार यानी दूसरा भाव। आप पूरी की पूरी\r\nटेबल के अनुसार इस कुंडली में जो जो पॉइंट\r\nदिया हुआ है वह लिखते चले जाएं। जैसे नंबर\r\nचार के नीचे 25 तो हमने यहां पर 25 लिखा\r\nहुआ है। नंबर पांच में 34 तो हमने यहां पर\r\n34 लिखा हुआ है। यहां पर 30 नंबर छह में\r\nतो यहां पे 30 लिखा हुआ है। नंबर सात पे\r\n24 तो यहां नंबर सात 24 जो कि पांचवा भाव\r\nहै। इस तरीके से 34 21\r\n24 29 36 27 और 22 यानी इसी टेबल के\r\nअनुसार\r\nहमने जो हर भाव के जो नंबर है वो लिख दिए।\r\nअब इसमें आपको कुछ सूत्र को समझना होगा।\r\nहर भाव में जो नंबर मिला हुआ है\r\nउसका एवरेज 28 नंबर मिनिमम होना चाहिए।\r\nजिस हाउस को 28 नंबर मिले हुए हैं।\r\nयानी कि वह भाव अपने से संबंधित जो जो\r\nचीजें उसे जीवन में आपको देनी है वो आराम\r\nसे देगा। अपनी दशाओं के अनुसार देगा। कम\r\nमेहनत से भी देगा। पर जिस हाउस में 28 से\r\nज्यादा नंबर हैं, वह भाव अच्छा है।\r\nमान लीजिए 30 नंबर आ गए, 32 आ गए, 34 आ\r\nगए, 35 आ गए। जितने नंबर बढ़ते चले जाएंगे\r\nऐसा समझो उस भाव की शक्ति बढ़ रही है।\r\nबढ़ी हुई है।\r\nदूसरा अगर 28 से कम हो जाते हैं यह अच्छा\r\nनहीं माना जाता। फिर से कहूं\r\nअगर 28 से कम हो जाते हैं तो अच्छा नहीं\r\nमाना जाएगा। अगर 22 से कम हो गए, 22 से भी\r\nकम हो गए तो हाउस डेंटेड माना जाता है।\r\nयानी उस भाव से संबंधित परिणाम\r\nबहुत मुश्किलों से मिलते हैं। बहुत ज्यादा\r\nसंघर्ष करना पड़ता है। और कभी-कभी तो ऐसा\r\nफील होता है कि परिणाम मिला नहीं मिला बात\r\nबराबर ही हो गई।\r\nज्यादा संघर्ष करके नुकसान उठा के ही वह\r\nचीजें जीवन में प्राप्त होती हैं। तो यह\r\nसूत्र याद रखेंगे\r\n22 से कम नहीं होने चाहिए किसी भी सूरत\r\nमें। 28 से कम नहीं होने चाहिए। अन्य भाव\r\nमें 28 से ज्यादा है तो अच्छे हैं। पर\r\nयहां अपवाद भी है। अपवाद क्या है? कुंडली\r\nका दूसरा भाव सेकंड हाउस\r\nऔर सेवंथ हाउस\r\nयह दो हाउस ऐसे हैं\r\nइनमें 22 से 28 के बीच में नंबर आना अच्छा\r\nमाना जाता है।\r\n22 से 28 सेकंड और यह सेवंथ\r\nइनमें यह नंबर\r\n28 से ज्यादा नहीं होने चाहिए। नहीं तो यह\r\nज्यादा होने से भी गड़बड़ हो जाता है।\r\nक्यों? क्योंकि यह मारक भाव है। आपकी\r\nकुंडली में सेकंड हाउस भी मारक होता है\r\nऔर सेवंथ भाव भी मारक होता है। अब यहां पे\r\nज्यादा नंबर कुछ ना कुछ गड़बड़ी कर देगा।\r\nवैसे तो हमने इसका एक डिटेल वीडियो\r\nएस्ट्रो पाठशाला में\r\nकम से कम सवा डेढ़ घंटे का बनाया हुआ है।\r\nआप पीछे जाकर के देखें। वहां पर भी आप देख\r\nसकते हैं। आज का यह वीडियो आपको फिर से\r\nतरोताजा करने के लिए मैं लेके आया हूं और\r\nऔर अच्छी तरह से आपको समझा रहा हूं। यह\r\nनियम आप समझ गए कि दूसरे भाव में और\r\nसातवें भाव में अगर आपको थोड़ा 28 से कम\r\nमिल रहे हैं तो चिंता का विषय नहीं पर 22\r\nसे कम मिल रहे हैं तो निश्चित रूप से\r\nचिंता का विषय है। अब आइए हम देखते हैं\r\nइसको समझते हैं कि नंबर कैसे काम करते\r\nहैं। पहले भाव में 31 नंबर हैं। बिल्कुल\r\nआपको समझ समझ में आ रहा है। चाहिए कितने?\r\nमिनिमम 28\r\nअगर 28 से ज्यादा है, यह क्या दिखाता है?\r\nपहला भाव हमारी सोच को दिखाता है। हमारी\r\nग्रो करने की सोच को दिखाता है। हम कितना\r\nबड़ा सोच सकते हैं? यह उसको दिखाता है। तो\r\nयहां पर यह दिखा रहा है कि भाई बंदा का 31\r\nनंबर आए हैं। बंदे की सोच बड़ी है। बंदा\r\nकुछ बड़ा करके दिखाना चाहता है। छोटे से\r\nउसको बहुत तसल्ली नहीं हो रही है। उसको\r\nबड़ा करने का ख्वाब है, सपना है। पर क्या\r\nकर पाएगा कि नहीं कर पाएगा? इसके लिए अन्य\r\nभावों को देखना पड़ेगा। वह अलग सूत्र है।\r\nसेकंड हाउस में 25 नंबर कोई बुरा नहीं।\r\nआपको बताया था 22 से 28 के बीच में होना\r\nचाहिए।\r\nदूसरे भाव से धन,\r\nवाणी और कुटुंब का सुख, खानपान का सुख\r\nदेखा जाता है।\r\nतीसरे भाव में 34 नंबर\r\nयह भाव एफर्ट्स का दिखाता है। यानी ऐसा\r\nव्यक्ति एफर्ट्स बहुत करता रहता है। और\r\nअगर यह नंबर पहले भाव की अपेक्षा ज्यादा\r\nहैं। यह ध्यान रखिएगा आपकी सोच से ज्यादा\r\nएफर्ट्स हाउस में ज्यादा नंबर ये कोई खास\r\nअच्छी बात नहीं कहते। कह रहे हैं कि जो जो\r\nआपकी सोच है\r\nवह एफर्ट जो होता है वह राइट डायरेक्शन\r\nमें नहीं होता है। वहां पर कंफ्यूजन बहुत\r\nहै। बहुत बड़ा एक गैप आ जाता है।\r\nकुछ नियम ऐसे हैं इसमें कि किस भाव में\r\nकिस भाव से ज्यादा नंबर होने चाहिए, किस\r\nमें कम होने चाहिए। वो पूरा का पूरा मैथ\r\nहै।\r\nतो इसमें 34 नंबर आ गए। बंदा एफर्ट्सफुल\r\nहै।\r\nचौथे भाव में जहां से हम कंफर्ट जोन को\r\nदेखते हैं, अपना घर देखते हैं, मन की\r\nशांति देखते हैं, जमीन जायदाद देखते हैं,\r\nप्रॉपर्टी देखते हैं। यहां पर 30 नंबर है।\r\nतो हम क्या कहेंगे यहां पर कि यार चौथा\r\nभाव ठीक है। इसमें ज्यादा प्रॉब्लम नहीं\r\nहै। 28 से ज्यादा है। तो इट्स वेरी गुड।\r\nदेखा कितनी आसान टेक्निक है। अब आप लगे\r\nपड़े हो। यह देखने के लिए कि चौथे भाव का\r\nस्वामी बुध है। वह कहां बैठा है, किसके\r\nसाथ बैठा है, कौन सा ग्रह देखता है। फिर\r\nवह नवमश में क्या स्थिति है? और बहुत फिर\r\nडिवीजनल चार्ट्स में जाना पड़ता है।\r\nसर्वाष्टक वर्ग बहुत आसान तरीके से आपको\r\nएक सेकंड में बता देता है कि किस भाव में\r\nकमजोरी है या किस भाव में ताकत है।\r\nअब देखें यहां पे चौथे भाव से संबंधित तो\r\nमामला ठीक आ गया। पर जब हम पंचम भाव में\r\nजाते हैं, जहां पर हम प्रेम देखते हैं,\r\nसंतान देखते हैं, हमारी क्रिएटिविटी देखते\r\nहैं। हमारी कला देखते हैं। हमारा पैशन\r\nदेखते हैं। यह भविष्य भाव है। पंचम भाव\r\nकिसी भी सूरत में कमजोर नहीं होना चाहिए।\r\nपर यहां देखिए\r\n24 नंबर मिले हुए हैं। 28 से कम हो गए। तो\r\nइन सभी चीजों में कमजोरियां मिलेंगी\r\nऐसे व्यक्ति को और ऐसा व्यक्ति भविष्य को\r\nलेकर के चिंतित और कंफ्यूज आपको समझ में\r\nआएगा। अच्छा अब आपसे कितना प्यारा सूत्र\r\nहै। अब मैं पूछूं भाई ऐसा क्यों? सीधे\r\nकहिए 28 से कम नंबर है। 28 से कम नंबर है\r\nतो ठीक है। उसके ऊपर क्लेरिटी नहीं है।\r\nअगर 28 से ज्यादा नंबर होते\r\nतो फिर उसकी क्लेरिटी बहुत अच्छी हो जाती।\r\nअब यह संदेश भी है उसके लिए कि भाई पंचम\r\nभाव कमजोर है तो पंचम भाव के लिए कुछ ना\r\nकुछ कीजिए आप नहीं समस्या में फंस जाओगे।\r\nछठा भाव में 34 नंबर है। 34\r\nवेरी गुड। यह नौकरी का जॉब का जॉब का हाउस\r\nहै।\r\nमुकदमाबाजी,\r\nजॉब, कंपटीशन ये सब देखा जाता। 34 बहुत\r\nबढ़िया हो गया। नौकरी रोजगार के लिए बहुत\r\nबढ़िया चीज हो गई है। क्योंकि 28 से\r\nज्यादा है। और यह छठे घर को याद रखो। अगर\r\nआप नौकरी में सफलता चाहते हैं तो 28 से\r\nऊपर नंबर ही होने चाहिए।\r\nविवाह स्थान नंबर सातवां यहां 21 नंबर है।\r\nइट्स मीन यह प्रॉब्लमेटिक एरिया है। जहां\r\n22 से कम हो गए। यहां पर तो नियम था दूसरे\r\nमें और सातवें में 22 और 28 के बीच में\r\nचाहिए। पर 22 से नीचे बिल्कुल नहीं चाहिए।\r\nतो यह प्रॉब्लमेटिक एरिया हो गया। आठवें\r\nभाव में 24\r\nयहां पर भी थोड़ा कमजोर है।\r\nभाग्य भाव में 29 वेरी गुड।\r\nअच्छा है।\r\n29 नंबर है। पर इसके मेरा अपना अनुभव कहता\r\nहै। इस भाव में 24 और 28 के बीच में होने\r\nचाहिए। नवम भाव में मैंने जिन लोगों के भी\r\n28 से ज्यादा देखे हैं। कई बार यह लोग\r\nमेहनत में कमी छोड़ देते हैं। और बहुत ढंग\r\nसे मेहनत नहीं कर पाते। जबकि एफर्ट्स\r\nबार-बार करते रहते हैं। प्रयास चीजों को\r\nलेने के लिए बार-बार प्रयास करते हैं। पर\r\nयहां पर फिर भी हम इसे अच्छे की श्रेणी\r\nमें रख देते हैं। क्योंकि ऐसे व्यक्ति को\r\nअपॉर्चुनिटी मिल जाती है।\r\nयह है कर्म स्थान। वेरी गुड।\r\n36 नंबर 36 एक्सीलेंट हो गया। आप देख रहे\r\nहैं ज्यादा नंबर कहां मिला है? 31 34 34\r\nऔर फिर पहुंच गया 36\r\nयानी सभी भाव में सबसे ज्यादा नंबर\r\nकर्म भाव में मिला है।\r\nयह बात बहुत अच्छी है। कर्म भाव में भूल\r\nकरके भी कम नंबर नहीं होने चाहिए। अगर\r\nकर्म भाव में नंबर कम हो जाएंगे तो\r\nव्यक्ति अपनी आजीविका कैसे चलाएगा?\r\nधन उसके पास बेचारे के पास कहां से आएगा?\r\nक्योंकि वह आजीविका को सेटल ही नहीं कर\r\nपाएगा। तो इट्स एक्सीलेंट। यह बहुत बढ़िया\r\nभाव हो गया। अब हम चलते हैं लाभ भाव में।\r\nलाभ भाव में 27 नंबर है। यह बड़ा ध्यान से\r\nसमझना है। यह सारी गड़बड़ हो गई। बिग\r\nमिस्टेक आप कहेंगे जी अभी तक तो आपने ऐसी\r\nरिएक्शन नहीं दी। मात्र 27 ही नंबर है।\r\nऐसी रिएक्शन तो आपने 24 पर भी नहीं दी।\r\nहां, यह अभी समझाऊंगा आपको। क्यों नहीं?\r\nलाभ भाव में 27 नंबर बिल्कुल भी सहन करने\r\nयोग्य नहीं है। इसका मतलब समझेंगे तो आप\r\nहैरान हो जाएंगे। सूत्र समझिए।\r\nभाग्य से ज्यादा कर्म में नंबर होने\r\nचाहिए।\r\nभाग्य में जैसे 29 है कर्म में ज्यादा है\r\nअगला सूत्र कर्म से ज्यादा लाभ में नंबर\r\nचाहिए तो व्यक्ति अपने काम सेटिस्फाई होगा\r\n36 और 27 इसको ऐसा समझ लीजिए एक व्यक्ति\r\n₹36 का काम करता है परंतु उसे पैसा ₹27\r\nमिलता है\r\nयानी जितना वह डिर्व करेगा उसके अपेक्षा\r\nउसको लाभ कम मिलेगा। अब इसको एक और सूत्र\r\nसे समझते हैं। कभी-कभी नौजवान यह चाहते\r\nहैं कि हमें यह बताया जाए हम कंफ्यूज है\r\nकि हम नौकरी करें या बिजनेस करें।\r\nतो उसका एक कंपैरिजन हम लोग करते हैं\r\nअक्सर कि इस व्यक्ति को नौकरी करनी चाहिए\r\nया खुद का काम करना चाहिए या बिजनेस में\r\nजाना चाहिए। तो नौकरी में देखो कितने नंबर\r\nमिले हैं। 34 आप खुद ही बता दोगे। आज के\r\nबाद से अपनी कुंडली खुद खोल के बता दोगे\r\nकि मुझे नौकरी करनी है कि मुझे बिजनेस\r\nकरना है। सिंपल गेम है ये। अगर ग्रहों में\r\nघूमते रह गए तो घूमते ही रह जाओगे भैया।\r\nयह मैं आपको बता दूं।\r\n34 नंबर नौकरी में मिले। सेल्फ\r\nएंप्लॉयमेंट का हाउस होता है सप्तम भाव।\r\nसेल्फ एंप्लॉयमेंट।\r\nयहां तो कहानी गड़बड़ चल रही है। सेल्फ\r\nएंप्लॉयमेंट होता है। आप डॉक्टर हैं। अपना\r\nक्लनिक खोल के बैठ गए। आप ज्योतिषी हैं।\r\nआप अपने सिंगल एस्ट्रोलॉजी कंसल्टेशन दे\r\nरहे हैं। आप सिंगल सिंगल जो भी काम करते\r\nहैं। आप छोटे दुकानदार हैं। वो आप सप्तम\r\nभाव से देखा जाएगा। अब आप बिजनेस में आते\r\nहैं। आपने एक टीम खड़ी की। आप बिजनेस में\r\nघुस गए। तो आपको 36 नंबर तो आपको कंपेयर\r\nकरना है कौन सा ज्यादा है? तो आप कहेंगे\r\nयह तो बड़ा आसान है। जी 36 नंबर ज्यादा है\r\nतो इसका मतलब व्यक्ति को बिजनेस करना\r\nचाहिए।\r\nयह बिजनेस की बात आ गई। अब आगे ट्विस्ट\r\nआता है। ट्विस्ट किस चीज का है? समझिए\r\nबात। खबरदार ऐसे केस में बिजनेस जब तक ना\r\nकरें जब तक कर्म स्थान से ज्यादा नंबर लाभ\r\nमें ना आ जाए।\r\nनौकरी में तो हर कोई सोचता है मैं ज्यादा\r\nमेहनत करता हूं पर मुझे कम मिलता है। वह\r\nसहन कर किया जा सकता है। पर जहां पर खुद\r\nकी पूंजी लगी है, खुद का पैसा लगा हुआ है,\r\nवहां पर स्थिति बड़ी नाजुक हो जाती है।\r\nऐसा व्यक्ति लॉस खा सकता है। वही है ₹36\r\nव्यापार में लगाएगा, ₹27 निकाल के लेके\r\nआएगा। तो क्या करना चाहिए? अगर यह रेशियो\r\nनहीं बैठता भाग्य से ज्यादा कर्म कर्म से\r\nज्यादा लाभ वाला रेशियो गड़बड़ा हो जाता\r\nहै\r\nतो सीधा जॉब पर शिफ्ट कर जाना चाहिए अगर\r\nजॉब में 28 से ज्यादा नंबर हैं तो\r\nवैसे तो मित्रों इसकी पूरी एक क्लास हो\r\nसकती है। कम से कम पांच से सात दिन इसके\r\nऊपर चर्चा की जा सकती है। इतना बड़ा है यह\r\nएक दूसरे से कंपेयर किया जाता है। किसका\r\nकिससे कंपेयर करके किसका किससे कनेक्ट\r\nकरके करने का बड़े सारे तरीके हैं इसके\r\nबहुत सारी टेक्निक्स हैं। पर मैं\r\n12वें भाव की बात करूं तो 22 नंबर आ रहा\r\nहै। अगेन 22 और 28 के बीच में तो ज्यादा\r\nखराब नहीं है। अब सूत्र समझें।\r\nहर हालत में 28 से कम ही होना चाहिए।\r\n12वें भाव में। ये ज्यादा पावरफुल नहीं\r\nहोना चाहिए। और किससे ज्यादा पावरफुल तो\r\nभूल के भी ना हो। आपके धन भाव से ज्यादा\r\nना हो। यह धन भाव है। सेकंड हाउस और यह\r\nखर्च का भाव है। देखो साहब इधर से धन आ\r\nरहा है और इधर से धन जा रहा है। धन आने का\r\nमार्ग\r\n25 पॉइंट मिला हुआ है। धन जाने का मार्ग\r\n22 पॉइंट बच गए। कभी-कभी कुंडलियों में यह\r\nहो जाता है यहां 25 मिला होता और यहां 26\r\n27 मिल जाता है। ऐसे व्यक्ति बार-बार कहते\r\nहैं कि क्या करें?\r\nहमारे पास किसी प्रकार की बरकत ही नहीं हो\r\nरही है। पैसा तो बहुत कमाते हैं पर हाथ\r\nमें कुछ बचता ही नहीं है। यानी कि व्यक्ति\r\nभी कंजूस है। व्यक्ति पैसा बचाने के विषय\r\nमें बड़ा भारी तरीके से सोच विचार करता\r\nरहता है। 22 नंबर अच्छे हैं। खराब नहीं\r\nहै। तो मैंने यह आपको बताया कहां पे खराब\r\nहै, कहां पे अच्छे हैं। इसका विश्लेषण\r\nइसको और तरीके से भी समझा जा सकता है।\r\nजैसे धर्म त्रिकोण\r\nधर्म त्रिकोण\r\nधर्म त्रिकोण क्या होता है? जी 1 5 9 1 5\r\n9 के नंबर को गिन लो आप। एक में आए 31\r\nपांच में आए 24 और नौ में आए 29। तीनों को\r\nजोड़ लो। अगर हम इसको जोड़ें\r\nतो चार\r\n84 नंबर आ रहे हैं।\r\n84 को तीन से भाग कर दीजिए।\r\n28 आ जाएगा। इसका मतलब धर्म त्रिकोण अच्छा\r\nहै। आप धर्म त्रिकोण का कंपेयर अर्थ\r\nत्रिकोण से कर सकते हैं। अर्थ त्रिकोण से\r\nपता चलता है रुपया पैसा कितना जीवन में\r\nरहेगा। एसेट्स कितने रहेंगे आपके पास? काम\r\nत्रिकोण यानी आपकी कामना पूर्ति। आपकी\r\nइच्छाएं कितनी पूरी हो पाएंगी? उस त्रिकोण\r\nको जोड़िए आपस में। तीन सात 11 यह काम\r\nत्रिकोण होता है। 4 8 12 यह मोक्ष त्रिकोण\r\nहोता है। मोक्ष के बारे में आपका क्या\r\nख्याल है? कुछ लोग मोक्ष के प्रति बहुत\r\nज्यादा\r\nललायित रहते हैं कि किस तरह मोक्ष प्राप्त\r\nहो जाए। तो यह सब चीजों के बारे में विचार\r\nके मामले में सर्वाष्टक वर्ग जो है का यह\r\nसूत्र लगाया जा सकता है। आप भी अपनी\r\nकुंडलियों में लगा करके देखें और पाएं कि\r\nक्या रिजल्ट निकल कर के आता है। कौन सा\r\nभाव कमजोर है और कौन सा भाव मजबूत है। जो\r\nभाव कमजोर है उससे डरिए मत। चैलेंज तो\r\nआएगा। ऐसा नहीं कह रहा कि डरिए मत का मतलब\r\nवहां से समस्या नहीं आएगी। वहां से चैलेंज\r\nआएगा। बी मेंटली प्रिपेयर। आपको मेंटली\r\nप्रिपेयर रहना है। बट आपको उसको सही करने\r\nका उपाय भी खोजना है। तभी जाकर के ज्योतिष\r\nसीखने का आपको लाभ मिलेगा। अन्यथा कोई लाभ\r\nनहीं मिलेगा। तो सर्वाष्टक वर्ग का यह\r\nवीडियो आपको कैसा लगा हमें जरूर लिख करके\r\nबताएं। धन्यवाद।"},{"topic":"गजकेसरी योग का असली सच जो कोई नहीं बताता","text":"गजकेसरी योग क्या होता है? कैसे बनता है?\r\nऔर कैसे फलित होता है? कि ऐसे व्यक्ति के\r\nजीवन में हर प्रकार का सुख, प्रसिद्धि,\r\nयश, मान, सम्मान, रुतबा सब चीज होती है।\r\nगजकेसरी योग नेताओं की कुंडलियों में\r\nमिलता है, कलाकारों की कुंडली में मिलता\r\nहै। सेलिब्रिटी लोगों की कुंडली में\r\nगजकेसरी योग का मिलना बहुत आम बात है। पर\r\nदिक्कत जब होती है जब आम सर्वसाधारण लोगों\r\nकी जन्म पत्रिका में भी यह गजकेसरी योग बन\r\nजाता है। क्या कारण है कि हमारा कुंडली का\r\nगजकेसरी योग काम क्यों नहीं कर रहा है?\r\nनमस्कार दोस्तों मैं सुनील वशिष्ठ।\r\nमित्रों आज का जो यह टॉपिक है यह है गजके\r\nकेसरी योग पर। गजकेसरी योग क्या होता है?\r\nकैसे बनता है? और कैसे फलित होता है?\r\nअक्सर गजकेसरी योग साधारणत मिल ही जाता\r\nहै। यह कोई दुर्लभ योग नहीं।\r\nपर दिक्कत जब होती है जब गज केसरी योग के\r\nबारे में ज्योतिषीय ग्रंथों में पढ़ते हैं\r\nतो उसमें तो बहुत अच्छा अच्छा लिखा हुआ\r\nहै। गजके केसरी योग में लिखा हुआ है कि\r\nऐसे व्यक्ति के जीवन में हर प्रकार का\r\nसुख,\r\nप्रसिद्धि,\r\nयश, मान, सम्मान, रुतबा सब चीज होती हैं।\r\nअक्सर यह योग उच्च पदाधिकारियों के पा की\r\nकुंडलियों में मिलता है। नेताओं की\r\nकुंडलियों में मिलता है। कलाकारों की\r\nकुंडली में मिलता है। सेलिब्रिटी कलाकारों\r\nकी सेलिब्रिटी लोगों की कुंडली में\r\nगजकेसरी योग का मिलना बहुत आम बात है। पर\r\nदिक्कत जब होती है जब आम सर्वसाधारण\r\nलोगों की जन्म पत्रिका में भी यह गजकेसरी\r\nयोग बन जाता है। तो फिर बाबू कहते हैं कि\r\nगुरु जी क्या कारण है कि हमारा कुंडली का\r\nगजकेसरी योग काम नहीं कर रहा। यह काम\r\nक्यों नहीं कर रहा है? तो इस पर भी आज हम\r\nचर्चा करेंगे। सबसे पहले हम कहते हैं गज\r\nकेसरी योग होता क्या है? देखिए जैसा कि\r\nनाम से ही विदित है। गज और केसरी। गज का\r\nमतलब होता है हाथी।\r\nऔर केसरी का मतलब है शेर सिंह\r\nकि व्यक्ति का धनधान्य इतना होता है\r\nव्यक्ति के पास कि उसके घर में हाथी भी\r\nखाना खा ले। हाथी खाना खाने का मतलब यह है\r\nकि वो इतना लोगों को भोजन करा सकता है।\r\nइतने लोगों को पालने में सक्षम होता है।\r\nउसके घर में नौकर, चाकर बहुत लोग होते\r\nहैं। और हर तरह की ऐशो आराम की चीजें होती\r\nहैं। बहुत सारी चीज सर्वसाधारण के\r\nदृष्टिकोण से देखें तो बेफिजूल के खर्चे\r\nहोते हैं। वह जिन्हें अक्सर कह देते हैं\r\nना नवाबी शौक हैं। भाई क्या करें? बिना\r\nमतलब का पैसा खर्च रहे हैं क्योंकि पैसे\r\nकी तो कोई कमी ही नहीं। जी हां, यह हाथी\r\nपालने वाली बात है। कहते हैं ना हाथी पाल\r\nरखा है इसने। तो जी हां शेर का मतलब रुतबे\r\nसे है।\r\nजिस स्थान पर वह रहता है उस इलाके में वह\r\nप्रसिद्ध होता है। इसके अलावा वो दूर-दूर\r\nतक प्रांत में और कभी-कभी तो गजकेसरी योग\r\nआपको देश और विदेश में भी प्रसिद्धि\r\nदिलाता है। और अब यह कहने की आवश्यकता ही\r\nनहीं कि उसके जीवन में लग्जरी होती है,\r\nगाड़ी होती है। तो सब छोटी-मोटी बातें\r\nहैं। जब इंसान का रुतबा इतना बड़ा बढ़\r\nजाता है और लोगों और उसमें बांटने की\r\nकैपेसिटी इतनी ज्यादा हो जाती है तो यह तो\r\nसब छोटी मोटी चीजें हैं। तो इसे कहते हैं\r\nगजकेसरी योग। अब गजकेसरी योग टेक्निकली\r\nकैसे बनता है? तो सबसे पहले देखें कि व्रत\r\nपर प्राशर हो शास्त्र में क्या श्लोक लिखा\r\nहुआ है। चंद्र गुरुभ्याम केंद्र गति\r\nचंद्रमा से गुरु केंद्रगत हो। साथ के साथ\r\nसमझाता भी जाता हूं। चंद्रमा आपने यह\r\nदेखना है आपकी जन्म पत्रिका में चंद्रमा\r\nकिस स्थान पर बैठा है। मान लीजिए कि\r\nचंद्रमा आपकी कुंडली में दशम भाव में बैठा\r\nहै। यह मैं मान रहा हूं। आप भी कुंडली खोल\r\nलीजिए अपनी और देखिएगा कि चंद्रमा कुंडली\r\nके 12 भाव में से कहां पर बैठा हुआ है।\r\nजहां पर भी बैठे\r\nउससे\r\nया तो उसके साथ यानी नंबर एक पर\r\nनंबर चार अपने से चौथे स्थान पर नंबर सात\r\nअपने से सातवें स्थान पर नंबर 10 अपने से\r\n10वें स्थान पर इसे ही केंद्र कहा जाता\r\nहै। एक चार सात 10 ये केंद्र स्थान है।\r\nजैसे कि चंद्रमा से गुरु\r\nउसी के साथ ही बैठ गया। पहली चीज ये हो\r\nगई। फिर अगला क्या है? उससे चौथा\r\nएक दो तीन चार तो अपने से चौथा या गुरु\r\nयहां पर बैठ जाए\r\nतो यह अपने से चौथा हो गया। चंद्रमा से\r\nफोर्थ\r\nपांच छ सात\r\nअपने से सातवा\r\nयहां पर बैठ जाए या\r\nगुरु अपने से दसवा\r\nअब आपको समझ में आया या तो इधर बैठ जाए\r\nया\r\nइधर बैठ जाए या सप्तम में या दशम में\r\nतो इसे कहेंगे\r\nचंद्रमा से गुरु केंद्र में आ गया तो पहली\r\nकंडीशन तो यह है कि चंद्रमा से गुरु\r\nकेंद्रगत हो जाए। अब इसको दूसरे तरीके से\r\nदेखते हैं। आप कहेंगे जी तो केंद्र में ही\r\nबना दिया। कोई बात नहीं भाई। दूसरी कंडीशन\r\nको देखते हैं। मान लीजिए आपकी कुंडली में\r\nचंद्रमा जो है यहां पर बैठ गया\r\nनवम भाव में तो यहीं से गिनना शुरू करो।\r\nएक दो तो एक गुरु यहां बैठ गया। दो\r\nतीन चार यदि गुरु यहां बैठ जाए पांच छ\r\nसात। गुरु यहां बैठ जाए 8 9 10 गुरु यहां\r\nबैठ जाए\r\nएक\r\nचार सात और 10\r\nये भी केंद्र बन गया अपने से एक चार सात\r\n10 इन स्थानों पर चंद्रमा से गुरु\r\nविराजमान है। चंद्रमा से केंद्रगत हो गया।\r\nआगे क्या कहते हैं? सर्वोच्च मित्र\r\nक्षेत्र संस्थे\r\nया तो इन दो ग्रहों में से एक ग्रह\r\nस्वराशि का हो जाए या उच्च का हो जाए। यह\r\nकंडीशन बहुत इंपॉर्टेंट है। अक्सर लोग इस\r\nकंडीशन को ही भूल जाते हैं। या तो स्वरा\r\nराशि यानी कि स्वयं की राशि में ग्रह बैठा\r\nहो या उच्च का बैठा हो या अपने मित्र राशि\r\nमें बैठा हो। यह बैठना जरूरी है। गजकेसरी\r\nसंज्ञक\r\nस्याध्य\r\nसर सुखावः\r\nइस प्रकार से गजकेसरी योग बन जाता है और\r\nयह हर तरह से सुख ऐश्वर्य और भोग देने में\r\nसक्षम\r\nयोग है। गजकेसरी योग राजयोग के ही समकक्ष\r\nहोता है। क्योंकि हर चीज देता है आपको तो\r\nऐसी कोई कमी नहीं देता। तो दूसरी कंडीशन\r\nबड़ी इंपॉर्टेंट है। जब भी चंद्रमा से\r\nगुरु केंद्र में हो, आपको यह देखना जरूरी\r\nहै कि इन दोनों में से एक ग्रह सौग्रही या\r\nउच्चिका\r\nया मित्र राशि में हो तो यह योग बनता है।\r\nप्लस अब एक और कंडीशन क्योंकि हमारी\r\nबातचीत चल रही है कि साहब ऐसा है कि यह\r\nयोग कब असफल कब हो जाता है? गजकेसरी योग\r\nभंग कैसे होता है? इसको समझना भी बहुत\r\nजरूरी है। यह बड़ा इंपॉर्टेंट है। गजकेसरी\r\nयोग भंग भी बड़ी जल्दी होता है। अब सपोज़\r\nकरो एक कुंडली है।\r\nयहां पर गुरु उच्च के बैठ गए\r\nऔर यहां पर चंद्रमा बैठ गए। अब आपने देखना\r\nहै कि किस प्रकार से यह चीज बनती है। गुरु\r\nउच्च के हैं।\r\nचंद्रमा मेष राशि का गजकेसरी योग बन गया।\r\nयदि\r\nराहु चंद्रमा के साथ या गुरु के साथ कोई\r\nपाप ग्रह विशेष करके राहु\r\nया केतु\r\nऔर चंद्र अगर बैठ जाए गुरु के साथ\r\nयहां गुरु के साथ राहु बैठ जाए जैसे मान\r\nलो राहु आ गया या केतु आ गया तो मामले को\r\nगड़बड़ कर देगा\r\nअगर गुरु के साथ\r\nबुध आ गया\r\nतो भी यह योग को भंग कर सकता है।\r\nचंद्रमा के साथ चंद्रमा किसके साथ नहीं\r\nहोना चाहिए? शनि के साथ ना हो, राहु के\r\nसाथ ना हो, केतु के साथ ना हो, सूरज के\r\nसाथ ना हो।\r\nइनके साथ नहीं होना चाहिए। अब एक और\r\nकंडीशन\r\nइनके साथ तो बिल्कुल नहीं बैठना चाहिए।\r\nकिसी भी तरह के पाप प्रभाव से मुक्त होना\r\nचाहिए। और दोनों के दोनों पाप ग्रहों से\r\nमुक्त होंगे तो उतना ही अच्छा क्वालिटी ऑफ\r\nगजकेसरी योग होगा। मतलब उसकी क्वालिटी\r\nबहुत इंप्रूव होती चली जाएगी।\r\nअब इसमें आपको क्या देखना है कि चंद्रमा\r\nऔर गुरु आपने क्या देखेंगे?\r\nचंद्रमा और गुरु का बलाबल डी नाइन चार्ट\r\nमें चंद्र\r\nऔर गुरु की स्थिति को\r\nनवमश कुंडली में नवमश कुंडली में अध्ययन\r\nकरें।\r\nयह बहुत जरूरी है। कभी-कभी\r\nडी1 चार्ट में ऐसा लगता है कि गज केसरी\r\nयोग परफेक्टली बन गया।\r\nपर जैसे ही नवमश कुंडली पर नजर जाती है\r\nचंद्रमा\r\nयदि नवमश में कमजोर पड़ गया नीच राशि में\r\nहो चला गया या अच्छे भाव में नहीं गया पाप\r\nग्रह से ग्रसित हो गया तो गजके केसरी योग\r\nअपना पूरा अच्छा परिणाम नहीं देगा या गुरु\r\nग्रह\r\nनवमाश कुंडली में कमजोर पड़ गया तो भी\r\nजो है यह गजकेसरी योग पूरी तरह से फलित\r\nनहीं होगा। अब आप कहेंगे जी कैसे समझे हम?\r\nबहुत सारे वीडियोस हमने एस्ट्रो पाठशाला\r\nYouTube चैनल पर बना रखे हैं कि ग्रह किस\r\nतरह से नवमश कुंडली में जाकर के कमजोर हो\r\nजाते हैं और किस प्रकार से ग्रह कुंडली\r\nमें खासकर नवमश कुंडली में बली हो जाते\r\nहैं वह भी आप जाकर के देख सकते हैं। खैर\r\nअगर यह नवमश कुंडली के अंदर\r\nअच्छे हो जाते हैं। अच्छे मतलब उनका\r\nप्लेसमेंट अच्छी हो, पाप ग्रहों से ग्रसित\r\nना हो तो यह बहुत शानदार\r\nयोग होता है। हर तरह का सुख, समृद्धि,\r\nऐश्वर्य, आराम, नौकर, चाकर, लग्जरी,\r\nऐश्वर्य, धन, दौलत शहरत का बेहतरीन यह योग\r\nबनाता है और शानदार चीज है। अब आप में से\r\nबहुत सारे लोग कहेंगे, अरे यह तो हमारी\r\nकुंडली में भी है यह योग। तो, अ पर अब\r\nकरें क्या इसका? अगर किसी के कुंडली में\r\nभी गजकेसरी योग है\r\nऔर कोई चंद्रमा कमजोर हो रहा है, बलहीन हो\r\nरहा है या गुरु कमजोर हो रहा है। किसी भी\r\nकारण से गुरु अस्त हो गया, गुरु नीच राशि\r\nमें चला गया। कोई भी कारण हो सकता है।\r\nबहुत रीजन हो सकते हैं गुरु ग्रह के कमजोर\r\nहोने के। तो, ऐसे जातकों को यह योग तो\r\nकाफी हद तक असर नहीं देगा। पर फिर भी मैं\r\nकहता हूं जिसके चंद्रमा और गुरु आपस में\r\nकेंद्रगत हो जाए\r\nउन्हें जीवन में बार-बार\r\nजब भी मौका लगे हाथी की सवारी करनी चाहिए।\r\nजी हां।\r\nकई जगह आपने देखा होगा मेलों में या कई\r\nपिकनिक स्पॉट पर हाथी वाले होते हैं और वह\r\nबिाने का कुछ चार्ज लेते हैं तो आपसे वह\r\nजो भी मांगे आप दे दीजिए। बहुत बड़ा उपाय\r\nहै। जब जब मौका लगे आपको हाथी की सवारी\r\nकरना है। दूसरा\r\nहाथी जो भी चीजें खाने में खाता है। हाथी\r\nको खाना यानी जो लोग आप दाने में बहुत\r\nसारी चीजें खिलाते रहते हैं। पक्षियों को\r\nचुगाते हैं, कुत्तों को चुगाते हैं। तो\r\nहाथी वाले से ही बात करके कि हाथी क्या\r\nखाता है? जितना आपकी शक्ति सामर्थ्य हो\r\nहाथी का एक समय का भोजन या पूरे दिन का\r\nभोजन आप उस हाथी वाले को दे सकते हो। हाथी\r\nको खाने से भी हाथी को खाना खाना खिलाना\r\nहै।\r\nअभी आपने सुना होगा\r\nअंबानी साहब के सुपुत्र हैं। उन्होंने भी\r\nगुजरात के अंदर कुछ ऐसा ही खोला है।\r\nहाथियों के लिए स्पेशल खाना बनता है। है\r\nना? आपने खबर सुनी होगी। हां, यह भी एक\r\nबहुत ही सुंदर रेमेडी है। तीसरा ऐसे लोगों\r\nको केसर\r\nअपने भोजन में उपयोग में लानी चाहिए। केसर\r\nका उपयोग अपने भोजन में अवश्य करना चाहिए।\r\nअब आप लोग कहेंगे जी केसर तो महंगी है।\r\nकोई बात नहीं अपने पास। बहुत अच्छे ऑप्शन\r\nहै। आप हल्दी का उपयोग भी कर सकते हैं\r\nअपने भोजन में। भोजन का मतलब यह है हम\r\nकहेंगे सारे हल्दी का करते उन्हें हल्दी\r\nकी चाय पीनी चाहिए। एक गर्म पानी लीजिए और\r\nउसमें कच्ची हल्दी डाल दीजिए। बस वही आपकी\r\nहल्दी वाली चाय हो गई। उसको रोज डेली\r\nसूर्यास्त से पहले सुबह से लेकर के\r\nसूर्योदय से लेकर सूर्यास्त होने से पहले\r\nपहले उसको एक बार पी लेना चाहिए। है ना?\r\nकितना अच्छा? शरीर पर सोना जरूर धारण करके\r\nरखना चाहिए। ऐसे लोगों को शरीर पर सोना\r\nजरूर धारण करना चाहिए। शरीर पर सोना जरूर\r\nधारण करें।\r\nधारण करें। देखो है ना? बढ़िया उपाय बता\r\nदिया आपको। अच्छा गजकेसरी योग वालों की एक\r\nखासियत होती है। उनकी पहचान एक उनके पिता\r\nभी प्रसिद्ध आदमी होते हैं। उनके पिताजी\r\nभी रुतबेदार इंसान होते हैं। उनके पिता का\r\nभी हिसाब किताब बहुत अच्छा रहता है। या आप\r\nऐसे कह सकते हैं जब भी बच्चा जिसकी कुंडली\r\nमें गजकेसरी योग बन रहा है उसकी पिता की\r\nतरक्की उन्नति होने लग जाती है। घर परिवार\r\nमें सुख समृद्धि बढ़ने लग जाती है।\r\nजैसे-जैसे ऐसे जातक की उम्र बढ़ती है,\r\nबच्चे के परिवार में सुख समृद्धि आती हुई\r\nचली जाती है। है ना कितना प्यारा योग?\r\nअपने लिए भी अच्छा है और अपने परिवार के\r\nलिए भी अच्छा है। और क्या कर सकते हैं?\r\nपूछ कर करके ज्योतिषाचार्य की हेल्प से\r\nऐसे जातकों को जो है\r\nपीला पुखराज भी धारण कर सकते हैं। पीला\r\nपुखराज हटा देते हैं थोड़ा\r\nपांच नंबर पीला पुखराज।\r\nऔर क्या धारण करना चाहिए?\r\nपीला मोती\r\nपीला मोती भी धारण कर सकते हैं ऐसे लोग।\r\nहै ना? देखो कितने शानदार चीज हो गई। यह\r\nचीज धारण करने से उनके लिए बहुत बढ़िया\r\nअच्छा असर करता है। और क्या करना है उन\r\nलोगों को?\r\nसप्ताह में ही एक बार केसर वाले चावल।\r\nमीठे चावल। केसर वाले\r\nमीठे चावल।\r\nअच्छा जिनको डायबिटीज हो वह अवॉइड करिएगा\r\nइस रेमेडी को। जरूरी नहीं कहें गुरु जी\r\nआपने यह बताई थी तो हमें तो शुगर हम तो\r\nदबा के खा रहे हैं। यह नहीं करना। बिल्कुल\r\nनहीं करना है। डॉक्टर अलऊ नहीं करता है\r\nआपको। आपका शरीर अलऊ नहीं करता तो बाकी\r\nरेमेडी कर लें। केसर वाले मीठे चावल हफ्ते\r\nमें एक बार खाएं। नहीं हो सकता। कोई बात\r\nनहीं। महीने में एक बार खाएं। और क्या\r\nकरना है? इसको बड़ा लग्जरी बनाना है।\r\nड्राई फ्रूट्स मिला लें।\r\nजिनके कुंडली के अंदर यह योग बना हुआ हो,\r\nउन्हें अपनी हाइजीन का विशेष ध्यान रखना\r\nचाहिए। फूड की क्वालिटी का ध्यान रखना\r\nचाहिए। जितना अच्छे स्तर का भोजन करेंगे,\r\nबढ़िया वस्त्र धारण करेंगे, यह योग उतना\r\nही ज्यादा अच्छा फलदाई होता है। ठीक है?\r\nकैसा लगा यह वीडियो आपको? है ना? आप कमेंट\r\nबॉक्स में जरूर लिखिए। आज हमने आपको बताया\r\nगजकेसरी योग क्या होता है? कैसे बनता है,\r\nकैसे फलित होता है और कैसे भंग होता है?\r\nऔर आपकी कुंडली में है तो इसका उपाय कैसे\r\nकरें? हां, अभी तक अगर हमारे वीडियो को\r\nलाइक नहीं किया, शेयर नहीं किया और\r\nसब्सक्राइब नहीं किया है तो कर लीजिए।\r\nधन्यवाद।"},{"topic":"बाधक स्थान बाधक ग्रह बाधक ग्रह कब करेगा परेशान और कब करेगा मालामाल बाधक ग्रह का अर्थ व भाव","text":"यह बाधक ग्रह क्या होता है जैसे कि नाम से\r\nही पता लगता है वह ग्रह जो बाधा\r\nपहुंचाए फिर प्रश्न उठता है किस तरह की बाधा किस तरह की\r\nपरेशानिया अब कार्य कोई जिंदगी में एक ही प्रकार का तो होता नहीं हर व्यक्ति की सोच\r\nके अनुसार लाइफ के अनुसार उसकी मनोकामना के हिसाब से कार्य\r\nकी परिभाषा अलग अलग है अब किसी का यदि विवाह नहीं हो पा रहा\r\nतो उसके लिए बाधक जो बाधा आ रही है उसके विवाह के कार्य में आ अब किसी की नौकरी\r\nनहीं लग रही है तो उसके लिए नौकरी लगना अपने आप में ना लगना अपने आप में\r\nपरेशानी का एक कारण है तो बाधक ग्रह आपको बताता है कि आपके जीवन\r\nमें बाधाएं कहां से आ रही है कैसे आ रही है उनका\r\nस्वरूप क्या है और बाधा के रूप में कौन आपके सामने\r\nआएगा हमेशा ध्यान रखें एक कहावत है ना हमारे यहां कि किसी ना किसी को तो निमित्त\r\nमात्र बनना पड़ता है है किसी ना किसी को तो माध्यम बनना पड़ता है अच्छे के लिए भी\r\nऔर बुरे के लिए भी जब हम अपनी फाइल को किसी सरकारी आदमी के पास लेकर जाते हैं और\r\nवह रिफ्यूज कर देता है उसको काम को करने से तो हमारे लिए बाधक कौन हो गया वो अफसर\r\nही हमारे लिए बाधक हो गया अगर आपकी इच्छा है कि आपको एक मोटरसाइकिल मिल जाए और आपके\r\nपिताजी मना करते कि साहब मैं तो नहीं दिलाऊंगा तो इस समय पिताजी बाधक हो गए तो समय के\r\nअनुसार सिचुएशन के अनुसार\r\nबाधक स्थितियां बदलती रहती है पर एक होते हैं परमानेंट टाइप के बाधक\r\nपरमानेंट बाधक क्या होते हैं जो\r\nविचार हमारे ब्रेन में बाधक के रूप में\r\nडेवलप हो जाते हैं जो आदतें ब्रेन पैटर्न के रूप में हमारे अंदर\r\nडेवलप हो जाते हैं वही बाधा है या किसी चीज के प्रति\r\nपूर्वाग्रह वह हमारी बाधा है कि फला फलाना\r\nआदमी फलाना जाति का या फलाना मजहब का व्यक्ति ऐसा ऐसा होता\r\nहै उससे क्या करेंगे हम उससे डील नहीं करेंगे तो ये हमारे ब्रेन में उसके प्रति\r\nएक पैटर्न बन गया तो यह हमारी बाधा है तो बाधाएं कई प्रकार से अलग अलग रूप\r\nमें होती है ज्योतिष के संदर्भ में कैसे देखा जाता है बाधक ग्रह बाध केश कैसे देखा\r\nजाता है वह मैं बताऊंगा यह तो कार्य की बाधा हमारे वैदिक ज्योतिष में यह माना\r\nजाता है कि वह ग्रह जो आपकी स्पिरिचुअल\r\nग्रोथ में बाधा पैदा करे वह व्यक्ति\r\nजो आपकी स्पिरिचुअल ग्रोथ में प्रॉब्लम्स बन करर के सामने\r\nआए वोह भी बाधक है बाधक भाव का जो स्वामी\r\nहै वह बाद केश कहलाता है मैं आपको कुछ समय के लिए स्क्रीन पर लेकर के जाता हूं\r\nजिससे आपको समझ आए कि मैं क्या समझाने की कोशिश कर\r\nरहा आपके पास तीन प्रकार के लगन होते हैं\r\nचर लगन स्थिर लगन और द स्वभाव\r\nलगन चार लगन में कौन-कौन से आते हैं एक चार सात और\r\n10 स्थिर में कौन से आते हैं दो पाच आ\r\n11 द सभा में आते हैं तीन छ न और\r\n12 यह लगन की बात कर रहा हर लगन के हिसाब से बाधक भाव अलग अलग\r\nहोता है तो उसको तीन कैटेगरी में डिवाइड कर दि चर लगन एक कैटेगरी में दूसरी कैटेगरी में\r\nस्थिर लगन और तीसरी कैटेगरी में द स्वभाव\r\nलगन अब आइए समझते हैं चर लगन में जो बाधक भाव होता है वह गवा\r\nहै लेथ हाउस स्थिर\r\nमें नवम\r\nभाव और द सभाव में सप्तम\r\nभाव चर लगन में 11वां\r\nभाव स्थिर लगन में नौवा भाव और द सभाव में\r\nसप्तम भाव बाधक होता है\r\nयह समझ लीजिए अगर आप बाधक और बाध केश के कांसेप्ट को समझ गए तो आप इंसान की बहुत\r\nसारी प्रॉब्लम को सॉल्व करने में सक्षम हो\r\nजाते अगर व्यक्ति वास्तव में एस्ट्रोलॉजी\r\nको वैदिक एस्ट्रोलॉजी को सही ढंग से सीखे तो उसको कभी भी कॉम्प्लिकेटेड\r\nफार्मूला की रिक्वायरमेंट होती ही नहीं हमारे ऋषियों ने बहुत\r\nआसान तरह से इसको कहने का प्रयास किया गया था परंतु बाद में उसको कॉम्प्लिकेटेड बना\r\nदिया गया सिंपल सिंपल\r\nफार्मूले क्या है जिन व्यक्तियों का भी चर लगन चर लगन\r\nवाले व्यक्ति कौन है मेष लगन का व्यक्ति कर्क लगन का व्यक्ति तुला लगन का व्यक्ति\r\nऔर मकर लगन का व्यक्ति अगर आप में से कोई है तो हाथ खड़ा\r\nकरो आरपी शुक्ला साहब जो है मेष लगन के व्यक्ति हैं तो मेष लगन वालों के लिए\r\n11वां भाव बाधक भाव हो जाएगा अब गवे भाव का जो स्वामी बना वो कौन\r\nबना शनि ग्रह श तो शनि ग्रह कौन हो जाएगा बाध\r\nकेश यानी बाधक का स्वामी अब हमें समझना क्या है सूत्र अब\r\nयहां से शुरू होगा बाध केश यानी\r\nबाधी बाधक का स्वामी ग्रह कुंडली के जिस भाव में भी\r\nजाएगा वहां पर बाधा क्रिएट करेगा फिर से रिपीट कर कर रहा\r\nहूं बाद केश कुंडली के जिस भाव में भी\r\nजाएगा वहां पर बाधा क्रिएट करेगा और वो बाधा कैसी होती\r\nहै बाधा कैसी होगी\r\nसाइकोलॉजिकल साइकोलॉजिकल बाधा स्पिरिचुअल बाधा\r\nऔर पर्सनालिटी एरर तीन चीज हमेशा याद रखिएगा बाद केश तीन\r\nप्रॉब्लम पैदा करता है पर्सनालिटी एरर पैदा करता है साइकोलॉजिकल प्र परेशानियां\r\nसाइकोलॉजिकल\r\nमानसिक और स्पिरिचुअल तीन तरह की प्रॉब्लम्स एक बाद\r\nकेश ग्रह दे है अब हम कहे भाई यह तो लंबा प्रोसीजर\r\nहोगा अब यहां पर कंफ्यूजन लोगों का क्या उठता है चलो शुक्ला साहब का तो मान लिया\r\nकि साहब वो जो है ना शनि है तो शनि है तो प्रॉब्लम दे दे पर अगर किसी का बाधक ग्रह का\r\nस्वामी शुभ हुआ तो फिर क्या करें अगर किसी का बाद केश गुरु हुआ तो\r\nक्या करें शुक्र हुआ तो क्या\r\nकरे बात को तो वो अपने आप में प्रॉब्लम हा स्वाति जी\r\nबताइए कुछ कह रहे आप अच्छा ओके ओके बोल गुरु मेरा है हा हा मैं वही कह रहा हूं तो\r\nइंसान सोच में पड़ जाएगा भा अब इसको क्या माने यह बाधा पैदा करेगा नहीं करेगा\r\nनिश्चित रूप से बाधा पैदा करे तो एक तो तरीका यह है कि आप इनके सबके रट मारो कि\r\nगुरु क्या बाधा देगा बुध क्या बाधा देगा और सूर्य क्या देगा और शनि क्या देगा एक\r\nआसान तरीका भी है इसको याद करने का बता दू बहुत आसान तरीका है बाधी ग्रह को आप राहु\r\nकी तरह ट्रीट करें आप ऐसे इमेजिन\r\nकरें कि जहां पर आपका बादी बैठा है\r\nअगर वहां पर राहु बैठा हो तो क्या रिजल्ट देगा राहु साइकोलॉजिकल बैरियर्स क्रिएट\r\nकरता है ब्रेन में ब्लॉकेज डेवलप करता\r\nहै राहु का मतलब\r\nछाया हम अगर जिंदगी में तरक्की नहीं कर पाते तो उसके पीछे हम हमारे\r\nवहम हमारी अप ब्रिंगिंग हमारी नॉलेज हमारी थिंकिंग यही तो\r\nजिम्मेवार है वहम का मतलब क्या है जैसे एक मैं सिंपल\r\nबात बताता हूं जैसे एक बच्चा ऐसी फैमिली से आता है जिसके परिवार में सारे गवर्नमेंट जॉब\r\nमें तो सारे गवर्नमेंट जॉब में है या प्राइवेट जॉब में अगर उसने बंदे ने कहा मैं बिजनेस खड़ा\r\nकरूंगा तो सारे परिवार वाले उसको क्या कहेंगे दिमाग खराब है क्या ऐसा होता है\r\nक्या लुट जाएगा बर्बाद हो जाएगा देख फलाने का लड़का बर्बाद हो गया उसने 10 लाख खराब\r\nकर दिए उसने 20 लाख खराब कर दी उसको गाइडेंस मिली जीरो गाइडेंस मिली जीरो और\r\nनेगेटिविटी में कितनी मिली फुल बटा फुल अब वो क्या करेगा आधे अधूरे मन से\r\nप्रयास कर करेगा क्योंकि घर वालों ने बताया पैसा नहीं बर्बाद करना तो वो क्या करेगा वो प्रयास भी थोड़ा सा ही करेगा वो\r\nपूरे मन से प्रयास ही नहीं करेगा और जब आप व्यक्ति पूरे मन से प्रयास नहीं करता तो\r\nअवश्य ही फेल होता है जब तक आप पैशन की हद तक किसी को प्रयास\r\nनहीं करते आपको सफलता नहीं मिलती पक्का वो फेल हो जाएगा मान लो उसने\r\nलाख दो लाख रुपए लगाए बजट था 10 लाख का लगाए लाख दो लाख तो फेल हो गए वो बैठेगा\r\nनिश्चित बैठेगा अब वो फिर क्या कहेगा भाई अपना तो बस की बात नहीं है अपने\r\nतो डीएनए में बिजनेस नहीं है फिर घर वाले कहेंगे हां हां हां बिल्कुल हमने तो\r\nसमझाया था पहली ही कहा था चल रामलाल जी के यहां पर तेरे को नौकरी लगवा देता हूं मेरी बहुत चलती है तो यही तो बातें होती है अब\r\nउस बच्चे ने अगर दो-तीन साल नौकरी कर ली ही विल लूज द कॉन्फिडेंस ऑफ डूइंग द\r\nबिजनेस तो उसके मन में वहम बैठ गया कि बिजनेस तेरे बस का खेल नहीं है इसे कहते वहम वहम\r\nकेवल भूत प्रेत का ही नहीं होता बहुत सारी चीजों का वहम होता है अगर ऐसा हुआ तो क्या\r\nहोगा वैसा हुआ तो क्या होगा ऐसा करूंगा तो वैसा होगा वैसा करूंगा तो ऐसा हो यह तरह\r\nके वहम जो हमें सिखाए गए हैं जो हमें बताए गए हैं हमारे दोस्तों के\r\nद्वारा हमारे गुरुओं के द्वारा हमारे माता-पिता के द्वारा हमारी सोसाइटी के\r\nद्वारा और हमारे धर्म के द्वारा ये समझिए व कौन पैदा करता है व धर्म पैदा करता है\r\nधर्म मीस आप जिस बात को फॉलो कर रहे हो जिस स्पिरिचुअल प्रैक्टिस को आप फॉलो कर\r\nरहे हो वह भी आपके लिए बहुत बड़ी प्रॉब्लम हो सकती है य ध्यान रखना ये आएगा मैं आज\r\nबताऊंगा आपको इसी तरह आपके फ्रेंड भी आपके बाधक हो\r\nसकते आपका स्पाउस कैन बी रियल\r\nबाधक आपका स्पाउस कैन बी अ रियल बाधक आपका बिजनेस पार्टनर कैन बी रियल\r\nबाधक वह आपको बहुत परेशानी में डाल सकते हैं आपका मेंटर आपका गुरु कैन बी रियल\r\nबाधक पैसा कमाने के प्रति क्या आपकी सोच\r\nहै यानी कि पैसा कमाने के प्रति आपका क्या वहम है यह भी बाधक है फाइनेंस\r\nका सिंपल सी बात समझ में आई बाधक का मतलब है आपके ब्रेन में कुछ ऐसे पैटर्न बन गए\r\nहैं कुछ ऐसे ब्लॉकेज बन गए हैं जो आपके उस कार्य में बाधा पहुचा रहे हैं और हम अपने\r\nब्रेन के मैसेज के अनुसार ही एक्शन कर और जब वह ब्लॉकेज बने होते हैं नेगेटिव\r\nब्लॉकेज बने होते हैं तो हमें काम नहीं करने देते और यह उसी प्रकार से जैसे\r\nराहु हमारे दिमाग में बैरियर क्रिएट कर देता है ब्लॉकेज क्रिएट कर देता है छाया\r\nप्रकट कर देता है और हमें सही सेही डिसीजन नहीं ले पाते हम कंफ्यूज हो जाते हैं\r\nहो जाते तो क्या करता कन्फ्यूजन देता और अन देता अनसाने देता\r\nहै तो जहां पर बाद कीश ग्रह आपका बैठा है जिस भाव में\r\nभी वहीं पर आप राहु को इंपोज कर दो रा को रख\r\nदो अब जैसे स्वाति जी बता रही थी स्वाति जी आपका इसका मतलब मिथुन लगन है जो बाधक\r\nगुरु है नहीं सर शुक्र बोला मैंने शुक्र बाधक है धनु लगन की राशि है धनु लगन है तो धनु\r\nलगन में बुध ग्रह बाधक हो जाता है धनु लगन जो है द्वि स्वभाव लगन है\r\nस्वाती जी तो मैंने अभी लिखवाया ना द्वि स्वभाव लगन में सप्तम भाव बाधक हो जाता है\r\nहां जी तो आपने ये देखना है किय बुध ग्रह कहां बैठा है किस हाउस में बैठा\r\nहै बुध भी चौथे सर फोथ हाउस में हां\r\nजीी तो ये बुध ग्रह फोर्थ हाउस में बाधा क्रिएट\r\nकरेगा अब आदमी को समझना है कि बादा क्या क्रिएट करेगा यार बुध चौथे भाव में कंफ्यूज हो रहे तो सिंपल है आप इमेजिन\r\nकरना है कि फोर्थ हाउस में अगर हम राहु को बिठा देंगे तो क्या बा तो राहु चौथे भाव\r\nमें मन के ऊपर बाधा कट कर चौथा भाव मन है ना तो मन\r\nको ऊपर नीचे ऊपर नीचे कर देगा इसे कहते हैं चौथे भाव चौथा भाव जल का भाव\r\nहै चौथा भाव जल का भाव है राहु की लहर विचार रूपी लहरे तो उसमें मन में ज्वार\r\nभाटा आता रहता है ज्वार वाटा समझते हो सब पानी ऊपर चढ़ता\r\nहै फिर पानी नीचे आता है फिर ऊपर चढ़ता है फिर नीचे आ यही उसके मन की स्थिति हमेशा\r\nबनी रहती है समझ रहे हो बात को दैट इज अ बाधा अब राहु\r\nचौथे घर में बैठा है मन के घर में बैठा तो बाधा क्या क्रिएट करेगा राहु कौन है भूत प्रेत छाया शैडो\r\nवहम मन में कई तरह के वहम पैदा\r\nकरेगा अनसुलझे रहस्यों के प्रति जिज्ञासा पैदा\r\nकरेगा तो बहुत सारे ऐसी चीज तो चौथे भाव में राहु को रख लो साइकोलॉजिकल और\r\nपर्सनालिटी और ये सब में प्रॉब्लम पैदा कर देगा ट्स इट तो सिंपल है बट बाद केश को\r\nइग्नोर करना बहुत बड़ी प्रॉब्लम है ज्योतिष में बहुत बड़ी मूर्खता\r\nहै समझ ग बात तो यह इस तरह से बाधक ग्रह\r\nकार्य करेगा तो आपको एक टेकनीक मैंने ये बता दी क्या आ\r\nगया कि भैया जहां पर आपका बाद केज ग्रह बैठता है वहां पर ऐसे इमेजिन करो जैसे\r\nराहु बैठा हुआ है दूसरा फार्मूला\r\nकभी-कभी शुक्ला जी अभी लेंगे प्रश्न है नहीं तो मैं यही पर टिका रहूंगा दो सूत्र\r\nप येय बाधक भाव पूरा नहीं होगा अब होता क्या है कि जब एक्सपीरियंस\r\nबहुत लंबा हो जाता है ना तो आदमी एक राशि पर भी दो घंटे बोल सकता\r\nहै व बोलने के लिए शब्दों की कमी तो होती नहीं तो इसलिए सूत्र अभी अपना प्रिडिक्टिव\r\nवाला मामला चल रहा है तो कोई ऐसी क्लास चलाएंगे जिसमें प्रवचन वाला मामला होगा तो\r\nउसमें चलते रहेंगे तो यहां पर मैं कहना चाहूंगा सूत्र नंबर दूसरा यह है अगर बाद\r\nकेश ग्रह पाप ग्रहों के साथ बैठा\r\nहो अगर बात केज ग्रह है पाप ग्रहों के साथ बैठा\r\nहो या पाप ग्रहों के बीच में\r\nहो या पाप ग्रहों के द्वारा उसे देखा जाता\r\nहो तो यह प्रॉब्लम को बढ़ा देगा और इसे आप पास्ट लाइफ का कर्ष\r\nसमझे यानी पुराना कर्मा है पास लाइफ का कोई दृढ़ कर्मा\r\nहै जिसको इस जन्म में भुगतान करना ही\r\nपड़ेगा इससे बच नहीं सकते भुगतान कैसे होता है दो माध्यम से भुगतान होता है\r\nबीमारी के माध्यम से दूसरा रिलेशनशिप के\r\nमाध्यम\r\nरिलेशनशिप के माध्यम से और बीमारी के दो चीजें इंसान कभी भी अपनी जिंदगी में\r\nखराब नहीं करता खराब होने देना नहीं चाहता\r\nऔर कहीं पर भी कभी भी खरीदने के लिए मार्केट में नहीं जाता कोई बीमारी खरीदने\r\nजाता है कोई नहीं जाता कोई बेकार रिलेशनशिप खरीद के लेकर के आता है कोई इसलिए शादी थोड़ी करता है रिलेशनशिप बेकार\r\nहोंगे व इसलिए संतान भी पैदा नहीं करता कि भाई जो है खराब रिलेशनशिप\r\nहोंगे कोई हेलो कोई भी व होगा तो वह इन कार्यों को\r\nजानबूझ के नहीं करता फिर भी हमें जीवन में ऐसी चीजों का सामना करना पड़ता है और कुछ\r\nलोगों को लॉन्ग टर्म तक इन बाधाओं का\r\nसामना करना पड़ता है समझ गए बात को तो बात केश ग्रह जहा\r\nबैठा है वो तो बैठा है अगर गलती से वो पाप ग्रहों के साथ बैठ गया या पाप ग्र के बीच\r\nमें बैठ गया तो प्रॉब्लम बढ़ जाएगी अब व छोटी मोटी समस्या नहीं बची वो\r\nबहुत भारी बच ग और वो पास्ट लाइफ की है अब हम एक एक बात फिर वापस आते हैं फिर\r\nधीरे धीरे बढ़ेंगे चर लगन की हमारे य चर्चा चली पहले सबसे पहले चर लगन में एक\r\nलगन यानी मेष कर्क तुला और मकर जो लोग\r\nइनके है आप में से जैसे जी ने बताया\r\nमल तो 11वां भाव जो होगा वो इनका बाधक भाव\r\nहोगा तो अभी मैंने बाद के समझाया वो ग्रह है जो बाधक भाव में आकर के बैठेंगे वो भी\r\nबाधा क्रिएट\r\nकरेंगे जो ग्रह बाधक भाव में आकर के बैठेंगे वो भी बाधा क्रिएट करेंगे\r\nपर उनकी बाधा माइल्ड होगी थोड़ी होगी ज्यादा नहीं\r\nहोगी फिर लगन में नवम भाव तो नवम भाव में\r\nजैसे किसी का सिंह लगन है नवम भाव में कोई ग्रह बैठा है तो वह ग्रह भी उसके लिए बाधा\r\nहै द स्वभाव लगन धनु लगन कन्या लगन मिथुन लगन मीन\r\nलगन तो सप्तम भाव में जो भी ग्रह बैठा है वह भी बाधा क्रिएट\r\nकरेगा अब 11 भाव से क्या बाधा आती है गवा\r\nभाव इनकम से रिलेटेड होता है तो इनकम की प्रॉब्लम\r\nदेगा फ्रेंड्स हमारे\r\nमित्र कौन से मित्र जिनसे हमें लाभ मिलता है मित्र दो है भैया एक मन का मित्र होता\r\nहै जिससे कोई स्वार्थ नहीं होता कोई कमर्शियल लेनदेन नहीं वह बचपन का दोस्त है\r\nआपका मित्र जो मन में इत्र की तरह घुल जाए वही\r\nमित्र जो मन में इत्र की तरह गुल जाए वही मित्र यह है बचपन का\r\nमित्र जिससे लेन देन कुछ नहीं है बस वो अच्छा लगता है उससे बात करना अच्छा लगता\r\nहै एक वो मित्र है जिसे आप अपनी भाषा में आपके एसोसिएट कह देते हो जिनसे लेना देना\r\nचलता रहता है जिनकी वजह से जिसके कारण से आपको लाभ भी मिलता है इनके साथ आपकी ऊठ\r\nबैठ होती है यानी जो आप जिस जिस क्षेत्र में काम करते हो तो वहां पर भी मित्र बन\r\nजाते हैं आपके ही जैसे होते हैं वो आप ही की क्वालिफिकेशन के होते हैं जैसे हमारे अरविंद जी जो है प्रोफेसर रहे हैं रिटायर\r\nहो गए तो अब इनके जब ये कॉलेज यूनिवर्सिटी में जाते हैं तो इनके जैसे ही प्रोफेसर\r\nवहां मिलेंगे तो उनमें भी मित्रता हो जाती है पर वो बचपन के मित्र नहीं है तो वो\r\nइनकम ग्रुप के मित्र है वो थोड़ा बहुत प्लस माइनस है वो उन्हीं\r\nके लगभग लगभग बराबरी के है लगभग ल तो वो भी मित्रता वाले भा तो गवे भाव में\r\nवो वाले मित्र आ रहे जो कमर्शियल प्लेस पर या किसी लेनदेन की वजह से मित्र बने जो\r\nआपके लिए कभी हेल्पिंग हैंड बन जाते हैं या आपको मदद पहुंचाते हैं फाइनेंशली उदारी\r\nवाले नहीं मल जैसे कुछ लोग कमीशन बेस पेस प यार तू मुझे काम दे मैं तुझे दूंगा\r\nफलाना ड़ा यह सब या मैं तुझे मदद पंचांगा किसी भी प्रकार की\r\nये गवे भाव से आते या कोई ग्रुप्स ग्रुप्स भी जो होता है ना फेसबुक\r\nग्रुप होता है जो या ट ग्रुप यह भी कभी कभी वाधा बन जाता है भाई कभी-कभी ग्रुप के\r\nलोग सारे ही खिलाफ हो जाते हैं आपके कम्युनिटी का भी ग्रुप होता\r\nहै आपकी जाति का ग्रुप भी होता है है ना तो कभी-कभी आपके अपनी जाति के लोग आपके\r\nएकदम अगेंस्ट चले जाते हैं आपको परेशान कर देते हैं ये सब गवे\r\nभाव से आने वाली बाधा इनकम इनकम से रिलेटेड फ्रेंड्स और\r\nग्रुप्स स्पेसिफिक ग्रुप्स ये गवे भाव से आने वाली बाधाओं को दिखाता है अगर जिनका\r\nचर लगन है क्लियर हुआ अब जिनका रुक जाओ शुक्ला\r\nसाहब मैं इसी में घूम जाऊंगा नहीं तो गल में सिं लगन यानी कि स्थिर लगन नवम भाव\r\nनवम भाव क्या बाधा पैदा करेगा भाई नवम भाव तो बहुत बढ़िया भाव है ये तो भाग्य भाव\r\nहै तो जब भी नवम भाव का स्वामी स्थिर लग्न\r\nमें जहां पर जाकर के बैठेगा तो बाधा किस तरह की देगा स्पिरिचुअल बाधा गुरु के\r\nद्वारा बाधा पिता के द्वारा बाधा अब गुरु के\r\nद्वारा क्या बाधा मिलेगी गलत गाइडेंस\r\nमिलना आपके घर का बड़ा बुजुर्ग भी आपका गुरु होता\r\n है ठीक\r\nहै कई बार गुरु ही होते है ना फसा फसू लेते कई बार गुरु उनको बचार को लूट लाट\r\nलेते हैं या गलत काम करवा देते हैं वोह भी अपने आप में बाधा है और सलाह तो गलत मिल\r\nही सकती है इसमें कोई शक नहीं घर का कोई बड़ा बुजुर्ग आपको गलत सलाह दे दे फिर बाद में कहे यार हमारे तो दादा यार ऐसे ऐसे\r\nसमझाते थे फस गए हम तो उनके कारण समझ रहे बात को या हमारे टीचर ने ऐसा\r\nऐसा दिमाग में हमारे डाल दिया था जिसके कारण हम आगे नहीं बढ़ पाए कुछ भी\r\nतो यह नाइंथ हाउस की बाधा है अब आते द स्व\r\nलगन प द स्वभाव लगन\r\nमें सप्तम भाव बाधक है अब सप्तम भाव जो\r\nहोगा व क्या बाधा पैदा करेगा प्रॉब्लम इन\r\nरिलेशनशिप प्रम इन रिलेशनशिप बाय\r\nस्पाउस यह माइंड में ब्लॉकेज क्रिएट कर देगा पैटर्न क्रिएट कर देगा जो यह बताता\r\nहै दिमाग में बात बैठ जाएगी भाई तेरा जीवन साथी तो खराब है खराब रहेगा इसका कुछ नहीं\r\nहो सकता यह नहीं सुधरेगा हरियाणा में कते भाई\r\nयह ना सुधरे यह तो ऐसा ही\r\nरहेगा बिजनेस की प्रॉब्लम्स\r\nऔर ऐसी कोई बीमारी जिसको डायग्नोज करना\r\nमुश्किल हो जाए यह सप्तम भाव की बाधा\r\nहै क्लियर हो गया बहुत इजी लिखवा रहा हूं मैं\r\nआपको अगर सप्तम से आने वाली बाधा अगर सप्तम भाव बाधक है तो और यह द स्वभाव लग्न\r\nमें होगा न छन 12 याद रख अब अगला सूत्र\r\nदेखे अगर आपका बाद केश ग्रह अगर आपका बाद केश\r\nग्रह छठे भाव से आठवे भाव से और बवे भाव से एसोसिएटेड\r\nहै बाद केश ग्रह यदि छठे भाव से आठवे भाव\r\nसे बवे भाव से एसोसिएटेड है तो डीप सफरिंग\r\nहै सफरिंग जो आ रही है सफरिंग म जो बंदा जो परेशानिया जो है वो बड़ी डीप है म बड़ी\r\nगहराई तक गई हुई है पहुची हुई डीप पेनफुल\r\nसिचुएशन इनका समाधान धीरे-धीरे जरूरी होता\r\nहै यह सूत्र लिखते रहना बड़े काम के हैं यह सूत्र इससे एकदम क्लिटी के साथ चीज आ\r\nजाएंगी बिल्कुल ठीक बाधी यानी बाद केश जो ग्रह है बड़ा ध्यान\r\nसे देखना उसके बवे भाव में कौन सा ग्रह बैठा है सर सर सर इसको एक्सप्लेन करेंगे एक बार\r\nबाद केश बाद केश क्या है जैसे तुम्हारा धनु लगन\r\nहै और बाद केश कौन हुआ बुध बुध समझ में आ गई ना आपने यह देखना है\r\nयह बुध ग्रह कहां बैठा है उससे बारवा भाव बुध जहां बैठा उससे बारवा भाव तो जहां\r\nतुम्हारा बुध बैठा है उससे बारवा भाव तुम्हारा बारवा ही है\r\nतो बवे भाव में देखना है कि ग्रह कौन सा बैठा है अगर मैले फिक ग्रह बैठा है स\r\nसूर्य अगर मैल फिक ग्रह बैठा है पाप ग्रह बैठा है मतलब तो ये देवी देवताओं का\r\nअग्रेशन है एंगर है गुस्सा है मतलब कोई देवी देवता आपसे गुस्सा है अगर सूर्य बैठा\r\nहै तो समझो आपने पिछले जन्म में अपनी पावर का मिसयूज किया है\r\nया पिताजी से पंगा लिया इल\r\nट्रीटमेंट विद फादर प्रसाद जी मैं अभी आऊंगा आपकी बात पर\r\nभी आपने लिखा है सबसे पहले बस मेरा मकसद रहता है कि\r\nआपको एक बार कांसेप्ट क्लियर कर द फिर अपन बैठ के बात कर\r\nलेंगे तो बवे भाव में जो भी ग्रह बैठेगा वह पास्ट लाइफ के\r\nप्रॉब्लम को दिखाएगा अब शुभ ग्रह बैठा है तो ठीक पाप ग्रह बैठा तो गड़बड़ करेगा य\r\nसमझ लो चलो उसके ऊपर जब हम एग्जांपल लेंगे तो\r\nबात करेंगे फिर हम आगे एक और चीज को लेकर के चलते\r\nहैं आत्म कारक ग्रह यह याद रख लो बड़ा काम\r\nआएगा जो आपके सबसे हाईएस्ट डिग्री प्लेनेट\r\nहै वह ग्रह जिस ग्रह के पास सबसे ज्यादा डिग्री है वो आपका आतम कारक ग्रह है\r\nपुराने स्टूडेंट जानते हैं\r\nखैर भूल से भी ये आपका बाद केज आत्म कारक ग्रह के साथ कनेक्टेड नहीं होना\r\nचाहिए या आपका आत्मा कारक ग्रह आपके बाधक\r\nभाव में नहीं बैठना चाहिए नहीं तो यह आत्मा बंधन में होती है\r\nयह समझ लो यह बंधन है एक प्रकार का अभी रुक जाओ आर रुक\r\nजाओ वह आत्मा अपना रियल पर्पस ऑफ लाइफ नहीं\r\nजानती आपका आत्मा आपको बताती है ना कि ऑब्जेक्टिव ऑफ योर लाइफ क्या है सोल पाथ\r\nजिसे बोलते हैं मैंने बुक भी लिखी है और सोल पाथ के नाम से लिखी है ज्योतिष द सोल\r\nपाथ वो अपना रास्ता नहीं जानती रास्ता नहीं जानने का मतलब मैं समझाता हूं\r\nकई बार आदमी 50 साल का हो जाता है 55 साल का हो जाता है वो कहता है मैं कुछ करना चाहता हूं पर उससे पूछो क्या करना चाहता\r\nबो बस यही तो नहीं पता मैं क्या करना चाहता हूं करना चाहता हूं क्या करना चाहता हूं\r\nफिर उसके बा कई ऑप्शन होते हैं मैं यह भी करना चाहता हूं मैं यह भी करना चाहता हूं मैं यह भी करना चाहता हूं वो कहते कोई चार\r\nडिसाइड कर ले बोला कर लि अब इस चार में से बेस्ट कौन सा है फिर वो कहेगा चलो एक और\r\nटाा लेते तीन बच गए तीन में से बेस्ट कौन सा बोला तीनों में से कोई सा भी नहीं निकालू य सुनलो बात तीन तो मैं कम से कम\r\nकरूंगा ही करू और जो तीन करेगा इसका मतलब कुछ नहीं\r\nकरे एक वर्ड आता है अक्रिया जानते इस वर्ड के बारे\r\nमें इंग्लिश वर्ड है पर यह आया इटालियन शब्द से है आप अक्सर एक सुनते होंगे चीज\r\nको करना चाहिए हमारे बाबा जी लोग बहुत प्रवचन देते\r\nहैं ऐसे करना चाहिए है ना मैं भी बोलता हूं ऐसे करना\r\nचाहिए यह करना चाहिए और अगर आपने भी बोल दिया करना\r\nचाहिए तो यह अ क्रेशिया है मतलब ये कुछ नहीं करते यह माइंड की एक बीमारी है मानसिक\r\nबीमारी है कर दिया कर दे और कर\r\nदिया करना चाहिए इसका मतलब कुछ नहीं करेगा डॉक्टर कहेगा सुबह उठ कर के एक्सरसाइज\r\nकरनी चाहिए हां हां करनी चाहिए तुम्हें रोज किताब पढ़नी चाहिए हां हां बिल्कुल\r\nपढ़नी चाहिए तुम्हें रोज यह काम करना चाहिए तुम्हें भगवान का नाम लेना चाहिए\r\nहां हां करना चाहिए अगर जो कह रहा हां हां करना चाहिए वो कुछ नहीं\r\nकरेगा और हमारे 70 परट लोग इसी बीमारी का\r\nशिकार हैं वो कहते हैं करना चाहिए पहली बात उसे ये नहीं पता क्या करना चाहिए\r\nऔर दूसरी बात कोई उसे समझाता है और उसे बात अच्छी लगती है तो कहता है हां करना\r\nचाहिए मना नहीं करते कि नहीं करना चाहिए अब कोई आपसे कहे सच बोलना चाहिए तो आप\r\nक्या कहेंगे हा सच बोलना चाहिए इसका मतलब सच नहीं\r\nबोलोगे जिस चीज के लिए कह रहा हूं करना चाहिए उसको नहीं करोगे चलिए ये तो डिफरेंट वड है कभी\r\nमनोविज्ञान की क्लास चलेगी जब बात करेंगे तो यह बाधक का जो कांसेप्ट है यह इस\r\nप्रकार से\r\nहै अब आपके प्रश्नों का लेता हूं बड़ी लगता है कि क्यूरिसिटी जाग गई है और नए\r\nस्टूडेंट सो गए हैं सारे कैमरे पर आ जाओ यार मैं आप लोगों को गंदी आदत पड़ गई\r\nहमारे पुराने स्टूडेंट्स को तो कि बाबा जी के प्रवचन होंगे तो तो कैमरे पर आएंगे वरना नहीं आएंगे टेक्निकल चीज नहीं सुनते\r\nमैं टेक्निकल भी जानता हूं ऐसी बात नहीं है टेक्निकल एस्ट्रोलॉजी भी मुझे बहुत अच्छी सी\r\nआती आरंश बताओ सर आत्मा\r\n काही हा हा बताओ हो तो समझा\r\nनहीं आत्म का ग्रह बाध आत्म का ग्रह केस हो जाए तो तो तो फिर तो ही है गड़बड़ हो\r\nगई आत्म कारक ग्रह है अगर बाध के यानी बाधक भाव का\r\nस्वामी अगर बाधक भाव का स्वामी आत्म कारक हो जाए तो वह आत्मा कारक ग्रह जिस भाव में\r\nजाएगा वहां पर भी प्रॉब्लम पैदा करेगा यानी आत्मा की शक्ति उस भाव को भी\r\nप्रॉब्लम में डाल देगी जो कहते दो मन दो मन का नाम सुना होगा ना\r\nयह कर लू यह कर ल ना ना ऐसा करूंगा तो ऐसा होगा ऐसा करू तो ऐसा हो डबल\r\nमाइंडेड ये डबल माइंड वही है ज आत्मा आपके लिए दो डिसीजन देती एक नहीं देती अगर आपकी\r\nसल वन साइडेड डिसीजन दे दे तो यू कैन डू बट अगर वो दो डिसीजन दे करू के ना करू\r\nकरू के ना करू तो आप अनसा हो जाते हो यही तो बाद केश का रोल है वो आपको अनसा करना\r\nचाहता है और वो कर देता है और एक तरह से साइंटिफिक भाषा में कहे तो आपके ब्रेन में\r\nकुछ ब्लॉकेज तैयार कर देता है या कुछ पूर्वाग्रह आपके विचार आपके अंदर समाहित\r\nकर देता है जिससे ऊपर आप नहीं उठ\r\nपाते तो कई चीजें होती अभी एक\r\nसज्जन बारबार कर रहे थे क्या नाम था उनका जी शुक्ला जी शुक्ला जी नहीं एक\r\nप्रसाद जी थे प्रसाद जी प्रसाद जोरे हा प्रसाद जी\r\nबताइए सर ष लगन में शनि बाद भी और योग काक\r\nभी है बा का रिजट देगा रि देगा वो बाद का\r\nरोल भी अदा करेगा और वह योगा कारी ग्रह का\r\nभी रिजल्ट देगा दोनों काम एक साथ कैसे दे अभी मैं आप\r\nही की बात कर रहा हूं पहले एक बात को क्लियर कर लेते हैं ये बड़ा एक अत द्वंद\r\nवाली बात है न्यू स्टूडेंट्स के लिए कंफ्यूजन का विषय खड़ा हो जाता है वृष लगन\r\nमें शनि ग्रह महा योगा कारी होता है वो नवम भाव का\r\nस्वामी भी है दसम भाव का स्वामी भी है तो नवम और दशम केंद्र और त्रिकोण का मालिक हो\r\nगया तो योगा कारी हो गया शुभ हो गया और अगर बाधक की बात करें तो नवम भाव\r\nका स्वामी स्थिर लगन में बाधक हो गया तो शनि बाधक भी हो गया और\r\nयोगाकाराका कट करेगा अब यह डिपेंड क्या करता है कि दशाओं\r\nपर डिपेंड करता है जब 18 साल की मान लो वृष लगन में 18\r\nसाल की शनि की महादशा शुरू हो गई और बंदा तो खुश हो जाएगा एकदम से अरे\r\nवाह महा गाकारी ग्रह की दशा शुरू हो गई तो इसको दो पार्ट्स में डिवाइड कर लो न\r\nसाल और न साल तो लगन से पहले सबसे पहले अगर लगन से आप\r\nघूमना शुरू करो एक दो तीन चार पाच तो पहले कौन सा भाव आएगा नवम भाव आएगा कि दशम\r\nआएगा बताइए नवम आएगा नवम\r\nआया नवम भाव आएगा तो रिजल्ट नवम भाव के आएंगे कि दशम के\r\nआएंगे ना के आएंगे नाथ के आएंगे और नाइ क्या है बाधक नाथ बाक\r\nइसीलिए जब भी ना वृष लगन वालों के साथ ये दशा चलती है वो यह मान के चलते हैं कि अब\r\nहमारे दिन सुधर गए और उनको विचारों को पहले नौ साल बाधाओं का सामना करना पड़ता\r\nहै हार्डशिप बढ़ जाती है उनके जीवन में भागदौड़ बढ़ जाती\r\nहै अगले न साल दशम भाव की जिम्मेवारी\r\nअगले न साल क्या है दशम भाव की जिम्मेवारी अब दव के रिजल्ट देगा तो सक्सेस के रिजल्ट\r\nदेगा थ हाउस र फॉर सक्सेस अचीवमेंट्स नेम\r\nफेम फ बंदा कहेगा भाई साहब 9 साल तक कड़ी मेहनत की है जब जाके परिणाम\r\nमिले ऐसे ही कहेगा ना भया बहुत भगदड़ मचाई मैंने ऐसी बात तो इसका सिंपल मीनिंग\r\nपर ऐसा नहीं है कि वो बाधक नहीं कहलाएगा या यह भी नहीं है कि वो\r\nयोगाकाराका आगे तक का चला जाएगा वैसे आपने पूछ लिया तो मैं बता दूं क्योंकि जो टॉपिक\r\nहै ना हमारा हम उसी पर कंसंट्रेट करें अगर शनि ग्रह नीच का है और वह वक्री हो गया है\r\nतो नंबर एक बात वो नीच के परिणाम नहीं देगा ये सूत्र है ज्योतिष का शनि ग्रह नीच\r\nका है और वो वक्री हो गया तो नीच के परिणाम नहीं देगा ठीक है तो आज हम बाधक और बाद केश पर\r\nही बात करें ओके सर बोला बाद केश अगर का हुआ तो\r\nयछ नीच का हो गया तो पर वो नीच का तो फल दे ही नहीं रहा ना वक्री है\r\nवो सर सर आर्यांश और को भी पूछने दो किसी और को\r\nसारे कहेंगे आर्यांश ट्यूशन पढ़ता है प्राइवेट हा बताओ अब तो बोल बोलो जब तक\r\nकोई नहीं बोल रहा जब तक तो बोलो ठीक है सर व ऐसा ही था कि व बुध आत्मा काक भी है ना\r\nसररा कौन और बु बु सर बुध\r\nआत्म बा नहीं बकल मत लो और यह है सर दिग\r\nबलीय तो और भी अच्छी बात है और सर मारक बाधक भी है और भी अच्छी बात है देखो समझो\r\nइसको कैसे ज्योतिष में कोई भी सूत्र ओवरराइट\r\nनहीं होता यानी कि आप किसी को भी डस्ट बीन में नहीं डाल के डाल सकते किसी भी सूत्र को अब जैसे\r\nआर्यांश के केस लेते हैं ये सभी द स्वभाव लगन वाले अपने अपने केस को\r\nसमझ तो सप्तम भाव जो होता है उसका स्वामी जो है व\r\nबाद अब आर्यांश का क्या है वो लगन पर बैठ गया और यह थोड़ा लकी रहा उस मामले में लकी\r\nइसलिए रहा कि ये बुध ग्रह है और बुध ग्रह लगन में शुक्र के साथ बैठा तो बुध ग्रह जो\r\nहै एक तो अकेला नहीं बैठा अकेला बैठ जाता तो बत फस जाता मामला बड़ा गड़बड़ा जाता तो\r\nबड़ा विपरीत हो जाता तो लगन में जब बुध बैठा तो वह दिगली हो\r\nगया और दिगली ग्रह जो होता है उसे हम अच्छा ग्रह माना जाता यानी उसे दिशा का बल\r\nप्राप्त है पर अब यहां पर सूत्र दूसरा क्या आ रहा है बाधक भी है\r\nबाद केश तो अभी सूत्र क्या लिखवाया था बाद केश जिस भाव में\r\nबैठेगा वहां पर बाधा क्रिएट करेगा अब बाधा किसकी होगी तीन प्रकार की बाधा बताई मैंने\r\nआपको साइकोलॉजिकल पर्सनालिटी एरर और तीसरा मैंने क्या बताया था आपको\r\nस्पिरिचुअल स्पिरिचुअल एरर क्या बताया था स्पिरिचुअल एरच\r\nस्ल नेस बताया स्पिरिचुअल सर स्पिरिचुअल स्पिरिचुअल तो ये क्या करेगा ब्रेन प है\r\nबुध ग्रह तो ब्रेन में ब्लॉकेज बना दे ब्लॉकेज किस चीज के क्रिएट होंगे मैंने\r\nसेवंथ हाउस से क्या क्या चीज लिखवाई है रिलेशनशिप नंबर एक\r\nरिलेशनशिप पार्टनरशिप विद द स्पाउस सेकंड बिजनेस से रिलेटेड थर्ड मैंने क्या बताया\r\nऐसी बी डायग्नोज ना किया जा सके लंबे समय लंबे\r\nसमय तक वो डायग्नोज ही ना हो पाए तो यह तीन तरह के ब्लॉकेज है ब्लॉकेज अब ब्लॉकेज\r\nका मतलब समझ लेना कि राहु मान लो यहां प बड़ा आसान तरीका बुध को हटा दो एक मिनट के लिए तो आपने ऐसा मान लेना कि दिमाग पर\r\nराहु बैठ है अब राहु क्या पैदा करेगा कंफ्यूजन देगा इल्यूजन देगा\r\nस्ट्रेस वो अनसाइंड साइसिव बनाएगा वही तीन मामले\r\nमें एक तो बीमारी नहीं पता लगना देगा कौन सी है धंधा कौन सा करूं ये नहीं पता लगने\r\nदेगा आदमी हमेशा कंफ्यूज रहेगा धंधा कौन सा करूं कौन सा नहीं कर तीसरा अपने स्पाउस\r\nके बारे में स्पाउस अच्छा है कि बुरा है अच्छा है कि बुरा कंफ्यूज है डिसीजन नहीं ले पा\r\nरहा पूर्वाग्रह से ग्रसित हो गया पूर्वाग्रह से ग्रसित कोना मैंने अभी\r\nबताया ये नहीं सुधरेंगे ये नहीं सुधरेगी इसे कहते हैं\r\nपूर्वाग्रह की ब्रेन में बैठ गया है कि स्पाउस सुधरने वाला नहीं है इसका कुछ नहीं\r\nहो सकता तो ये अब बुध ने बाद के सोने के\r\nरिजल्ट दिए अब इसके सबसे ज्यादा रिजल्ट कब\r\nआएंगे दशा दशा दशा में तो दिग बली के आएंगे टेंशन मत\r\nलो ठीक है जब दशा नहीं होगी तो व्यक्ति इन\r\nतीन चीजों को लेकर के बड़ा कन्फ्यूज हो मेरी शादी किससे होगी वह कैसी होगी व\r\nअच्छी होगी कि नहीं होगी धंधा कौन सा करूं कोई बीमारी तो ना\r\nहो गई मुझे और हो गई तो कौन सी हो गई यही नहीं पता लग रहा समझ रहे हो आ तो ज्योतिष में बड़ी\r\nगहरी चीजें होती है इसलिए मैं ओपन नहीं करता चलिए और कोई प्रश्न पूछिए अगर शनि जो\r\nहै वक्री है और वृद्ध अवस्था में है आप च लगन में जो बाद केश है उससे ना सबको\r\nक्लियर होगा हा और वक्री है वो नहीं वक्री का तो कांसेप्ट मैंने अभी कराया नहीं आप\r\nलोगों को इसलिए आप अभी बकरी के साथ मत चिपको अच्छ हम अगली एक्सरसाइज की तरफ आते\r\nहैं यह देखो जहां पर भी आपका बाद कीश ग्रह बैठा है हा वहां पर इमेजिन करके देखो आपको\r\nअपनी बात समझ में आ रही है कि नहीं आ रही है आप अपनी जिंदगी में बाधाएं कहां फील करते हो वहां अपने ठंडे मन से सोचो क्या\r\nवहां से आपको कोई बाधा आ रही है और फिर अगर नहीं समझ में आ रहा है तो फिर\r\nबाधा नहीं इसमें अगर लगने से एक्सपेक्टेड हो जैसे आपने बताया कि क्रूर\r\nदेख रहा उसको कूर ग्रह से देखेगा तो सफरिंग डीप हो जाएगी और व अगर लग्नेश हो\r\nइसलिए पूछा कोई भी हो वो मुद्दा नहीं है कि लग्नेश है व पाप ग्रह\r\nहै देगा और य बा जैसे मृत अवस्था में है तब\r\nभी व वही फल देगा शुक्ला साहब मैं चौथी बार पढ़ा चुका हूं य चौथी बार पढ़ा रहा\r\nहूं आर्ट प्रेडिक्शन मेरे पुराने स्टूडेंट से पूछना मैंने यह मृत अवस्था और जवान\r\nअवस्था बताई ही नहीं किसी को अच्छा अच्छा क्यों नहीं बताई बुढ़ापा जो है ये स्टेट ऑफ माइंड है\r\nहमारे जगदीश जी सबसे नौजवान है अब देखो बिल्कुल नौजवान है ये जगदीश जी अभी आप\r\nकैसे मैं कह दू ये बर्ध अवस्था को प्राप्त हो सर मेरे से आगे तो प्रदीप जी\r\nहै प्रदीप जी है मेरे से सीनियर\r\nदूसरे को बूढ़ा बताने में एक सेकंड नहीं लगाया इसका मतलब अपने आप को जवान समझते\r\nहैं तो यही बात दिखा रहा था शुक्ला जी मैं मैं वो नहीं कह रहा सर लेकिन मैं बता रहा\r\nहूं कि सीनियरिटी मेरी नहीं बनती अच्छा देखो सीनियरिटी प लड़ाई हो जाएगी जगदीश जी\r\nमैं इसीलिए आपको यंग बता रहा हूं यंग आदमी अपनी उसके लिए लड़ता है उमर\r\nके लिए ठीक है थैंक यू सर थंक य\r\nआपको जब मैं कराऊंगा ग्रहों की जिन्हें शुक्ला साब वर्ध अवस्था या मृत अवस्था\r\nकहते हैं वह मिरेकल्स डिग्री होती है 29 डिग्री जीरो डिग्री और एक डिग्री यह तीन\r\nडिग्रियां मिरेकल्स डिग्री होती है मलब अच्छी मानी जाती है आत्म कार ग्रह वही\r\nबनेगा जो 29 डिग्री का हो आत्म कारक बनने के सबसे ज्यादा चांस उसी तो आत्मा कारक\r\nकैसे खराब मान ले हम उसको वो आपकी आत्मा को कैरी कर रहा है उसको बूढ़ा कैसे मान ले\r\nभाई और आत्मा तो बूढ़ी होती नहीं है समझ गए बड़ा लॉजिकल\r\nपॉइंट वो जैसे छोटे बच्चों को नर्सरी में समझाने के लिए डिग्रियां समझाने के लिए\r\nकुछ बातें शुक्ला साब बताई जाती है जब होते है ना अभी शैश अवस्था है अभी किशोर\r\nअवस्था हो गई अब यंग अवस्था आ गई अब अधेड़ उम्र आ गई और अब ये उम इतने डिग्री से\r\nडिग्री तक वो एक नर्सरी के बच्चे को बताने के लिए बताया जाता है ज्योतिष में जिसे हम बेसिक ज्योतिष कहते हैं पर चकि मैं फलित\r\nका अध्यापक हूं तो यह चीजें फलित में एकदम पलटी मार जाती है मलब फलित में हमारे काम\r\nनहीं आती बहुत ज्यादा जो हमारे न्यू स्टूडेंट होते हैं\r\nवो सबसे ज्यादा कहते हैं डिग्रियां और मैं डिग्रियां सबसे लास्ट में बात करता हूं बीच में जाकर के बात ही नहीं\r\nकरता हा रत्ना जी सर क्या चर ल चर राशि वाली कुंडली में\r\nमेष लगन की कुंडली है चर राशि है पहली मेरा चर लगन बो चर लगन अच्छा वो लगन लिखा\r\nमैंने राशि कर दिया चर लगन मेष लगन की उसम गवा भाव का बाद के शनि हुआ और शनि जो है\r\nवो दसव घर में है और वो के केतु के साथ है तो राहु की दृष्टि तो पड़ ही रही है तो\r\nराहु राहु मिलके राहु प्लस क्या हो गया रतना जी राहु तो बाद में\r\nदेखना पड़ोसी को बाद में देखना पहले तो यह देखना घर में ही कौन घुसाया शनि केतु हा केतु घुसाया पहले तो\r\nउसको सुलट पड़ोसी को तो बाद में सुलट लेंगे जो पहले घर में घुसाया सबसे पहली\r\nबात आज की क्लास के सूत्र के अनुसार ये बाद केश जो है दशम भाव में बैठ\r\nगया हां जी तो बाधा कहां पर क्रिएट होगी कैरियर कर्म भाव काम में काम में नॉट\r\nकैरियर कर्म में बाधा है सफलता मिलने में बाधा है थ हाउस फॉर सक्सेस किसकी सक्सेस\r\nकर्म की सफलता कर्म की सफलता अब यहां पर क्या हो\r\nगया केतु और बैठ गया केतु शुभ ग्रह के पाप ग्रह डिटैचमेंट मेफिक प्लेनेट मैं उसका\r\nरिजल्ट नहीं बोला मैं पाप ग्रह पाप ग्रह तो अभी क्या सूत्र लिखवाया कि अगर बाद केश\r\nपाप ग्रह के साथ बैठा होगा तो पेन डीपर होगा पेन ज्यादा गहरा\r\nहोगा व्यक्ति के दिमाग में दिल में कहीं पर यह बड़ा गहराई से होगा कि मुझे जो\r\nसफलता मिलनी चाहिए थी वह नहीं मिल पाई जो काम मैं करना चाहता था व काम नहीं कर पाया\r\nजो मैं करना चाहता हूं उसमें बाधाएं आती है उसमें परेशानियां आती है उसम दिक्कत आती है ये चीज बन\r\nहै पर जो गवा बा बाधक भाव है उसम जुपिटर\r\nऔर चंद म है हा तो केसरी योग हो गया हा तो\r\nवो और फस गए येय गए और वो फस गए और\r\nक्या वो भी उससे भी गलत हो गया गलत नहीं\r\nहुआ गुरु और चंद्रमा वो भी बाधा क्रिएट\r\nकरने का काम करेंगे व अपना फायदा भी करेंगे मैं ये नहीं कहा फायदा नहीं करेंगे पर वो फायदा\r\nइस प्रकार से होगा जो बाधा के रूप में\r\nआएगा अगर कुछ मिलेगा भी तो प्रॉब्लम्स के साथ प्रॉब्लम के साथ मिलेगा अब आप बिल्कुल\r\nएट समझ है ना हलवाई के यहां पर शादी कर लोगे तो डायबिटीज फ्री में मिल सकती\r\nहै समझे बात में मिठाई फ्री की है तो जाओ खाए जाओ खाए जाओ फिर पता चला शुगर हो गई\r\nजो फायदा शुरू में लग रहा था वो प्रॉब्लम में आ गया ठीक है तो फिर सर उसकी रेमेडी को\r\nछुपाए रेमेडी तो बस फिर यही तो खासियत है हमारी रेमेडी बताएंगे\r\nकल इसीलिए कहते हैं आप प्रसन्नता भरे शब्द भरा करो तो रेमेडी अच्छी अच्छी निकल के\r\nआएगी हां प्रवीन जी प्रवीन जी काफी देर से हैं हा प्रवीन जी आप स रत्ना जी ने पूछ\r\nलिया आंसर और आपने आंसर भी दे दिया रेमेडी के बारे में पूछना था तो मेरा क्वे ई हो गया नहीं रेमेडी के लिए भी मैं कल बात\r\nकरूंगा इस विषय पर क्योंकि लंबी बात चलेगी ठीक सर देखिए एक चीज मैं आपको बता दूं\r\nवैदिक रेमेडी होने होती है बिल्कुल डिफरेंट हो हम जिन्ह रेमेडीज बोलते हैं वो\r\nदरअसल एक मिक्सचर है मार्केट में एक मिक्सचर है वैदिक रेमेडीज बिल्कुल डिफरेंट\r\nतरीके से वैदिक के मापदंड के अनुसार चलती वैदिक का मतलब जो वेद से आया\r\nहै और वेद का मतलब जो ऋषियों के द्वारा छन छन करके आया वेद तो लिखे वेद व्यास जी ने\r\nफिर उनके ऊपर जो उसको किया उ ऋषियों ने किया ऋषियों ने उसके ऊपर रिसर्च की और\r\nरिसर्च करने के बाद जो चीजें निकल निकल करके आई है वह चीजें वैदिक कहलाती\r\nहै हम उपाय किसे मानते हैं हम उपाय दूसरे जो आजकल मार्केट में प्रचलित ता उन्हें\r\nउपाय मानते हैं हां भाई पीपल के नीचे सरसों का तेल का दीपक जला दिया कर अच्छा\r\nअच्छा तो फिर पीला तिलक लगा लिया कर तो फिर हम इसे उपाय मानते हैं उपाय की श्रेणी\r\nमें रखते और हिंदुस्तान में यह बिना ज्योतिषियों के भी उपाय मिल सकते हैं आपको\r\nघर घर में अच्छा शनि की साडे सती हो गई अच्छा ब काले कुत्ते को रोटी दे दिया कर घर वालों ने बता दिया उसने बचारे ने आके\r\nबताया पंडित जी ने सनि की साढ़े बताया अरे चिंता ना कर काले कुत्ते को रोटी दि आया\r\nकरते है ना तो सिंपल उपाय तो घर परिवार\r\nमें भी हम लोगों को मालूम है हमारी दादी नानी को पहले से ही मालूम है सारी रेमेडी नजर लग गई भाई जूता निकाल जूता\r\nघुमा सर के ऊपर से सात बार चोट मार हो गई नजर उतर गई कोई बंदा दुखी कर रहा है सपने में आ\r\nरहा है जूता उसकी फोटो प मार दे पाच सात बार वो आना बंद कर देगा तो रेमेडीज तो ये भी\r\nबट ये वैदिक रेमेडीज नहीं कही जाती क्योंकि वैदिक रेमेडीज की रूल्स है\r\nज्योतिष में कुंडली में कि फला ग्रह अगर वहां बैठा है तो क्या करें और फलाना ग्रह वो बैठा है तो क्या करें तो वहां पर इफ\r\nएंड बट होता है मैं यह समझाना चाह रहा मुझे समझाना पड़ेगा किस ग्रह से क्या\r\nदेवता निकल के आया किस ग्रह से क्या मंत्र निकल करके आ रहा है और अगर कहां पर यह\r\nसिचुएशन आ जाए तो आपको क्या करना है तब हमें इस केस को समझ में\r\nआएगा जो भी बाद के ग्रह है उससे बारवा जहां पर बाधक भाव का स्वामी बैठा है उससे\r\nबवे भाव में जो भी ग्रह बैठे आपने ध्यान रखना है पास्ट लाइफ में\r\nआपने उसका मिसयूज किया था उस ग्रह से रिलेटेड सिग्निफिकेंट\r\nगया मान लो बाद केस के एक भाव पीछे शुक्र बैठ गया इसका मतलब आपने शुक्र की चीजों का\r\nमिसयूज किया था शनि बैठा है तो शनि की चीजों का मिसयूज\r\nकिया शनि का मिसयूज क्या होगा आपने गरीबों को बड़ा सताया था बृहस्पति का मिसयूज क्या होगा आपने\r\nअपने ज्ञान के माध्यम से लोगों को बेकू बनाया यस जैसे वो बाबा राम रहीम है आपके\r\nआसाराम बापू है अब तो यह सेलिब्रिटी\r\nहै पहले से सेलिब्रिटी थे अब और ज्यादा सेलिब्रिटी हो गए जेल जाकर जेल जाकर\r\nके तो ये क्या थे इन्होंने ये आप इनको बेवकूफ नहीं कह सकती यह बहुत नॉलेजेबल\r\nपर्सन पर इन्होने अपनी नॉलेज का इस्तेमाल गलत कर दिया लोगों को उमराहा कर\r\nदिया तो अगले जन्म में क्या होगा इनके भी बाद केश के पीछे गुरु बैठा\r\nमिले इनके अगले जन्म की कुंडली में बाद केश ग्रह के पीछे गुरु बैठा मिलेगा और\r\nगुरु के साथ हो सके कित भी बैठ जाए तो गुरु चंडाल बना देगा भाई पिछले\r\nजन्म में भी गुरु चंडाल था तू गुरु नहीं था चंडाल साथ में\r\nभीता चंद्र हो अग जी चंद्र हो चंद्र का\r\nमतलब है मेंटल टॉर्चर हम या माता से इल\r\nट्रीटमेंट माता के साथ सही व्यवहार ना करना यह चंद्रमा को दिखाता है कहने का\r\nमतलब मेरा यह है जो भी बाद केश ग्रह से बारवा बैठेगा वो आपके पास्ट के कर्मा से\r\nकनेक्टेड है ये समझ तो आपने तीन चार मैंने पॉइंट\r\nबताए कि बाद के 6 आ 12 से एसोसिएटेड ना हो पाप ग्रह के साथ एसोसिएटेड ना हो और जो\r\nबाद के के बवे भाव में जो ग्रह बैठता है वह पास्ट लाइफ से कर्मा से कनेक्टेड\r\nहै उसके हिसाब से आज का होमवर्क अपने अपने बाद केज कहां कहा बैठे\r\nहैं मेलि फिक के साथ बैठे कि नहीं बवे में कौन बैठा है कौन नहीं कहीं वह आत्मा कारक\r\nके साथ तो कनेक्टेड नहीं इन सब मुद्दों की जांच करोगे जैसे सीबीआई जांच होती है ना\r\nऐसे हमारे ज्योतिष के स्टूडेंट्स के द्वारा जांच हो तो सब लोग किसी दूसरे की जांच ना करके अपनी ही कुंडली की जांच कर\r\nऔर सर अगर ग्रह नहीं हो तो बव भाव में ग्रह नहीं\r\nहो तो भावेश को ले लेंगे कोई बात नहीं खत्म हो\r\nगई ही नहीं तो टेंशन ही खत्म हो ग तो आप ये एक मिनट ये जो है आप सारे\r\nलिखना दिमाग में मत रखना लोग कहते हैं हमारे दिमाग में कुछ नहीं है दिमाग में\r\nदिमाग में कब फाइल सरक जाए इधर उधर पता ही नहीं चलता नहीं मेरे साथ तो बहुत होता देखो आप\r\nलोगों के साथ होता ना होता क् एक तो मेरे पास फोन बहुत आते हैं अब सुबह 9:00 बजे फोन आया मैं कहता हूं अच्छा मैं तुम्हारा\r\nयह काम करवा दूंगा फिर 9 ब पाट पर दूसरा फोन आया तीसरा फोन आया चौथे फोन तक आने के बाद मुझे मैं भूल\r\nजाता हूं 9 बजे वाले को क्या कहा था है ना फिर व एकदम से फर याय क्या हो गया तो ओ\r\nफिर आ भी जाता है समझ में पर कई बार एक आधा मिस भी हो जाता है वो कहता है दो घंटे\r\nपहले फोन कराता ओ माय गड दो घंटे पहले फोन कराता भाई अभी करवाता तेरा काम है ना तो\r\nफाइल में अच्छा जब तुरंत हम कहते ना करवा देंगे तब दिमाग में रहता है बिल्कुल करवा\r\nदेंगे इसमें दिक्कत ही नहीं है हमें तो प्रॉब्लम ही नहीं है मतलब हम करने को तैयार बैठे पर अगर हम उसे लिख\r\nले तो फिर वो काम हो जाएगा तो मैं उसी समय वो मैसेज दूसरे के पहुंचा देता हूं भा ये\r\nकाम कर द पता नहीं क्या पता मैं भूल जाऊ तो इसलिए लिखना अपनी कुंडली में लोगों\r\nको और कॉन्फिडेंस रहता है कि भाई मैं समझ गया बस दिमाग में दिमाग में कुछ नहीं\r\nहोता है ना हमारे मास्टर जी कहते दिमाग में तो भूसा होता है\r\nज्यादा दिमाग पर तबार मत करो हा रत्ना जी सर एक अलग सा क्वेश्चन पूछ लू जैसे हवन कह\r\nरहे हैं आज कल करने को नवरात्रि शुरू हो रही है तो उसके लिए घर में खुद करने के\r\nलिए थोड़ा सा कुछ बता सकते हैं पंडित जी से लई थोड़ी हो रही है कोई\r\nआपकी सर साउथ में या बेंगलोर में अच्छे पंडित नहीं मिलते बंगलोर में तो बहुत\r\nअच्छे पंडित मिलते है पर वो एक एक हवन का 21000 11000 ऐसे मांगते हैं सर हम ही कर\r\nले ना हम भी तो ज पढ़ लिए थोड़ा सा कुछ घर में कर सके सबसे पहले\r\nतो अगर विचार बनाइए प्लान बनाइए कि हम न दिनों तक करना क्या चाहते\r\nहैं अगर आपने दुर्गा सरसती के पाठ को\r\nपढ़ना है तो प्लान दूसरा है फिर घट स्थापना होगी पहले\r\nअच्छा ना घट स्थापना घट का मतलब होता है घड़ा जी या\r\nकलश और मिट्टी के बर्तन का ज्यादा फायदा होता\r\nहै जी और घट स्थापना करने के\r\nबाद आप पूजन वगैरह करें अब मैं कैसे समझाऊं पूजन फिर आप एक पूजन के आप है ना\r\nनित्य क्रम पूजा प्रकाश पुस्तक ले लो ओके बड़ी इजली है और अभी तो आपको इस पर\r\nभी मिल जाएगी क मिल जाएगी पीडीएफ फम में ले\r\nलेना वेबसाइट पर देख लेना कि मैं जो है नवरात्रि पूजन कैसे\r\nकरू उसमें भी आपको दिशा निर्देश मिल जाएंगे तो आपको देवताओं का पूजन करना होता\r\nहै नव ग्रहों का पूजन करना होता है देवी का पूजन करना होता है 64 योग का पूजन करना\r\nहोता है वह पूजन\r\nकरके जो मां दुर्गा का रण मंत्र है उसका मंत्र जाप करें\r\nऔर फिर दुर्गा सस्ती का पाठ और दुर्गा सस्ती का पाठ को करने में अगर आपको जो है\r\nदिक्कत आती है तो उसमें विधि भी दे रखी है सर वो करती वो तो हमेशा कर बस ठीक है उसको\r\nआप कर सते सर एक रिलेटेड क्वेश्चन दुर्गा सति में कोई बार बोलते कि पहला और आखरी\r\nदूसरा और बारवा क्या ऐसे करना चाहिए तो किताब उस तरीके से क्यों नहीं छ हु\r\nहै देखिए हमारे ऋषियों का जो है और हमारे गुरुजनों का एक बहुत बड़ा यह दिमाग में\r\nथा एक सूत्र है विद्या कंठ पैसा\r\nअं विद्या वही मानी जाती थी जो आपके कंठ में विराजमान है यानी कि जो आपके गले में\r\nतो उसे रटाना भी होता था अगर पुस्तक आपके हाथ में नहीं\r\nहै तो भी आप उस पाठ को कर सके अगर 40 50 वर्ष पूर्व चले जाए या\r\nबनारस में आज भी कई जगह परंपराएं हैं अगर जो है रुद्राभिषेक करने वाला ब्राह्मण अगर\r\nजो है रुद्री की पुस्तक को हाथ लगा ले तो समझे भाई ये है नहीं दमदार ी उसको कंठस्थ याद होनी चाहिए ऐसे\r\nही मां भगवती का उपासना करने वाले व्यक्ति को दुर्गा सप सती के 700 श्लोक इसमें 700\r\nशलोक देखो कमाल की बात गीता में भी 700 है और सात का रहस्य बड़ा गजब का हमारे य\r\nअल्टिम है ना पूरा अल्टम सात नंबर पर ही है तो श्लोक है इसमें और यह 700 शलोक\r\nकंठस्थ होने चाहिए और दुर्गा सरसती के कई मंत्र जो है बड़े प्रसिद्ध है\r\nसुप्रसिद्ध जो कि अक्सर आपने सुने होंगे फिर इसमें सट कर्म जो होते हैं\r\nहमारे तंत्र के क्षेत्र में भी बड़े प्रसिद्ध है जिसे शांति कर्म भी कहा गया\r\nहै मारण मोहन उच्चाटन विद्वेष यह जो है सम्मोहन य सट कमों में आता है तो\r\nऐसे में उसके मंत्र भी दिए गए हैं बड़ी गुढ है कहने का मतलब तो सब कुछ होना चाहिए\r\nएक दौर ऐसा भी आया था हमारे देश में जब हमारे ग्रंथों को जलाया जाता था हमारे\r\nमंदिरों को लूटा जाता था उनको ध्वस्त किया जाता था और विद्या समाप्त करने का भरसक\r\nप्रयास किया आपको जान के हैरानी हो हमारे जो असली तांत्रिक ग्रंथ थे व 90 पर\r\nजला दिए गए या विदेशों में भिती तो हमारे पास कुल ज्ञान ही 10 पर बचा है और उसमें\r\nसे भी 10 पर में से भी पूरे देश में 10 पर लोग भी नहीं है जो उस तंत्र विद्या को\r\nजानकारी रखते हैं आज कोई उनके ऊपर प्रवचन ही कर दे तो वही एनफ है उसका क्रियात्मक\r\nस्वरूप तो बहुत बड़ी बात है फिर भी मेरा यह मानना है कोई ना कोई आत्मा\r\nऐसी जरूर आएगी जो परमात्मा का अंश रूप होगी जो\r\nइस महान विज्ञान पर अपनी बात जरूर रखेगी इसलिए हमें अपने समाज में सनातन धर्म में\r\nबोलते रहना चाहिए चर्चा करते रहना जरूर कोई ना कोई योगी संत ऋषि कोई ना कोई\r\nमहर्षि कोई ना कोई वैज्ञानिक आएगा जो तंत्र को मंत्र को बहुत ही प्रमाणिक रूप\r\nसे सिद्ध करेगा और समाज में स्थापित तो करते रहिए रत्ना जी बिल्कुल\r\nकीजिए आपको बहुत-बहुत मुबारक हो कल शक्ति\r\nके नवरात्रि हैं शक्ति का आहवान कीजिए जय माता दी हा और उसमें बलि भी देनी पड़ती है\r\nरत्ना जी क्रोध की क्रोध की बलि दे देना लिख देना कि क्या मैं छोड़ रही\r\nहूं क्या पर्सनालिटी एरर जो भी होता है ना साइकोलॉजिकल नहीं पर्सनालिटी\r\nबाद के वसे समाप्त हो जाएगा वो अपने हस्बैंड से पूछना अपने खुद\r\nसे मत करना एकदम खत्म हो जाएगा स नि और फिर हवन\r\nकुंड में अग्नि जला कर के पर्ची पर लिखना और कना स्वाहा गायत्री मंत्र से गायत्री मंत्र तो\r\nशांति मंत्र है स्वहा मंत्र नहीं है स्वाहा\r\nसौधा चलिए आज का यहीं पर पूरा करते हैं हां सोविक जी\r\nआप कुछ बोलना चाह रहे हैं फिर चलते\r\nहैं सर एक सवाल था प्रणाम सर प्रणाम छोटा सा क्वेश्चन है सर ये म\r\nआपका जो\r\nमार्केशिटी बाश की सॉरी\r\nबा दोबारा बोलिए बाद बाध जिस भाव में बैठता है वहां भी भावेश का कुछ रोल होता\r\nहै नहीं नहीं भावे का नहीं बाध जिस भाव में बैठा है उस भाव से जो चीज आ रही है\r\nउसमें ब्लॉकेज लेकर आता है उसम अनने लेकर के आता है वहा पर ब्लॉकेज क्रिएट करता है\r\nओ बके म बाधा एक प्रकार की बाधा किसी का बादी चौथे भाव में बैठ गया तो चौथे भाव से\r\nबाधा फील होंगी चौथे भाव से फील कैसे होंगी भाई चौथा भाव तो मन है तो मन के\r\nअंदर बाधा चौथा भाव आपका अपना घर है चौथा भाव आपकी शांति है पीस है वहां पर\r\nबाधा जैसे कई लोग कहते घर में घुसते ही दिमाग खराब हो जाता बाहर सब कुछ ठीक तो\r\nबाधा कहा से आ रही है च घर से आ रही है समझ रहे हो तो ये होता है चलिए ठीक है धन्यवाद\r\nथैंक यू\r\nसर"},{"topic":"लग्न बलवान कैसे लग्न की रक्षा कौन सा ग्रह करता है","text":"नमस्कार एस्ट्रो पाठशाला में आप सभी का बहुत-बहुत\r\nस्वागत है। मित्रों, आप में से बहुत सारे\r\nदर्शक हमें हमारे कमेंट बॉक्स में जाकर के\r\nअच्छे-अच्छे सजेशन देते हैं। उन्हीं सजेशंस के अनुसार\r\nकुछ दर्शकों ने पूछा है कि गुरुजी कैसे जाने कि जन्म पत्रिका में लग्नेश हमारा\r\nकमजोर है या बलवान है। आज का यह वीडियो\r\nइसी टॉपिक पर रहने वाला है कि कैसे देखें हम अपनी जन्म पत्रिका में कि लग्नेश हमारा\r\nवीक है या लग्नेश हमारा पावरफुल है और\r\nपूछे भी क्यों ना क्योंकि लग्नेश के बारे में कहा जाता है कि लग्नेश सदैव\r\nहितकारी लग्नेश कभी भी हमें परेशान नहीं करता।\r\nलग्नेश जीवन के हर पक्ष के साथ जुड़ा हुआ है।\r\nजीवन का कोई भी रंग क्यों ना हो लग्नेश का बल हमें हमेशा मदद करता है। आप में से जो\r\nदर्शक नए हैं वो कहेंगे कि ऐसा कैसे? जी हां, यदि आपको धन में बढ़ोतरी चाहिए,\r\nलग्नेश बलवान होना चाहिए। आपको लोगों के साथ अच्छे रिलेशन बनाने हैं। लग्नेश ठीक\r\nहोना चाहिए। आपकी सोच मजबूत चाहिए। बड़ी सही है। विशाल चाहिए। लग्नेश बलवान चाहिए।\r\nआपको जीवन में सुख सुविधाओं का उपभोग करना है। और वह भी बैलेंस रूप से। लग्नेश अच्छा\r\nहोना चाहिए। जीवन में प्रेम चाहिए। लग्नेश अच्छा होना चाहिए। अच्छा जीवन चलाना है।\r\nलग्नेश अच्छा होना चाहिए। अच्छा करियर चाहिए। अच्छी जॉब चाहिए। अच्छा बिजनेस\r\nचाहिए। अच्छी सफलता चाहिए। सब में लग्नेश अच्छा होना चाहिए। और एक बात आजकल शादियां\r\nटूट रही हैं। रिलेशन टूट रहे हैं। बहुत जल्दी रिलेशनशिप खराब हो जाते हैं। एक\r\nअच्छी और सफल मैरिज चलाने के लिए भी लग्नेश की भूमिका बहुत अहम होती है। यानी\r\nकि आपने समझा जीवन का कोई भी पक्ष हो लग्नेश वहां पर अपना अहम रोल दिखाता ही\r\nदिखाता है। इसलिए आप सभी लोग अपनी जन्म पत्रिका खोल लें और आज जो मैं स्टेप आपको\r\nसमझा रहा हूं उस स्टेप के अनुसार आप देखते चले जाइए और आपको मालूम लग जाएगा आपकी\r\nकुंडली का लग्नेश कैसा है कैसा नहीं और यदि वीक है तो उस पर हम काम करेंगे। आइए\r\nसमझते हैं कि लगन से हम क्या-क्या चीजें देख सकते हैं। लग्न यानी कि जन्म पत्रिका\r\nमें पहला भाव। जी हां, यहां पर जो आप देख रहे हैं हमने येलो कलर मार्क किया हुआ है।\r\nयही लग्न है। चलो लिख भी देते हैं।\r\nलगन पूरी कुंडली का राजा होता है। इसके\r\nऊपर बहुत सी चीजें डिपेंड करती है। अगर लग्नेश बलवान हो जाए तो समझो यह भी एक\r\nपरमेश्वर का आशीर्वाद है। चलो देखते हैं\r\nसमझते हैं कि ऋषियों ने लग्न के बारे में क्या-क्या कहा है। आइए वृद्ध पराशर होरा\r\nशास्त्र में क्या लिखता है। लग्नम नाम शरीरस्य\r\nयानी कि लगन से शरीर देखा जाता है। शरीर\r\nपूरा का पूरा शरीर लगन के द्वारा ही देखा जाता है। अब इसमें हमारा स्वास्थ्य हमारा\r\nरंग रूप हम बाहरी रूप से देखने में कैसे\r\nलगते हैं? यह भी लगन से ही पता लगता है। तत्र सिधा सुभा शास्त्राज्ञा पाप का त द्व\r\nपरित गुणा यानी कि लगन को शरीर कहा गया है। यदि शुभ ग्रह लग्न में हो तो जातक\r\nज्ञानी वह शास्त्र में निपुण होता है। पाप\r\nग्रह हो तो विपरीत गुण होते हैं। कितनीता है। लाल किताब तो इसे कहती है जो लग्न है\r\nयह कुंडली का तखत होता है। यानी कि कुंडली का सिंहासन।\r\nजो भी ग्रह लग्न में विराजमान होता है बस वो जस्ट एक राजा की तरह ही होता है। अब\r\nयहां पर ऋषि क्या कह रहे हैं? पर वहां पर कह रहे हैं कि यदि लग्न में पाप ग्रह का\r\nबैठना वो अच्छा नहीं माना गया। पर शुभ ग्रह बैठ जाए तो व्यक्ति ज्ञानी होता है,\r\nशास्त्र का जानकार होता है, विद्वान होता है और सम्मानित होता है। यहां तक भी कहा\r\nजाता है कि वैसा व्यक्ति विद्वानों की सभा में भी सम्मान प्राप्त करता है। सबसे पहले\r\nसमझने का प्रयास करते हैं कि लगन से क्या-क्या देखा जा सकता है। सबसे पहले\r\nलग्न यानी कि आपका पहला भाव यानी कि शरीर वो अभी आपको पूरा समझाया कि शरीर से आपके\r\nबारे में क्या-क्या चीजें पता चल सकती है। ये एक ऐसा भाव है यह आपको बताता है कि\r\nजैसे आप लोगों से व्यवहार करते हो। यानी कि फर्स्ट मीटिंग में जब भी आप किसी से\r\nमिलते हो तो आप अपने किस प्रकार के गुणों का प्रदर्शन करते हो? यानी कि फर्स्ट\r\nअपीरियंस में फर्स्ट मुलाकात में आपका व्यवहार कैसा रहता है? जैसे कुछ लोग होते\r\nहैं पहली मुलाकात में बहुत अच्छे बने रहते हैं। पर जागे मुलाकातों में वो उसी प्रकार\r\nके गुणों का प्रदर्शन करेंगे कि नहीं करेंगे? यह थोड़ा डाउटफुल रहता है। परंतु\r\nजिनका लग्नेश अच्छा होता है, वह बहुत व्यवहार कुशल माने जाते हैं। दूसरा चीज\r\nस्वभाव। जी हां, यह स्वभाव हुआ बड़ा।\r\nज्योतिष में एक मान्यता होती है। अगर आप किसी की कुंडली को देखकर उसके स्वभाव को\r\nसमझ सकते हैं। उसके टेंपरामेंट को समझ सकते हैं तो आप बहुत कुछ उसके बारे में\r\nबता सकते हैं। बहुत कुछ उसको समझा सकते हैं। स्वभाव हमारे जीवन में बहुत\r\nमहत्वपूर्ण है। इस स्वभाव की वजह से ही कोई इंसान\r\nसोसाइटी में अच्छा या बुरा माना जाता है। परिवार के लोग अच्छे स्वभाव के फैमिली\r\nमेंबर के साथ बहुत हंसी-खुशी के साथ रहते हैं। उसके विपरीत यदि किसी के स्वभाव में\r\nकमियां आ जाती हैं तो समस्याएं बढ़ जाती हैं। वह खुद के लिए भी समस्या होता है,\r\nपरिवार वालों के लिए भी समस्या होता है और समाज और सोसाइटी के लिए भी बहुत ज्यादा\r\nसमस्या पैदा कर देता है। यह बहुत इंपॉर्टेंट एस्पेक्ट है लगन का। तीसरी चीज\r\nचरित्र बड़ा इंपॉर्टेंट है। चरित्रवान होना बहुत अच्छी बात है। क्योंकि चरित्र\r\nही डिसाइड करता है एक व्यक्ति अपने जीवन में किस मुकाम तक पहुंच सकता है। यहां पर\r\nवह पैसे वाली सफलता की बात नहीं चल रही है। पर चरित्रवार इंसान पर लोग ट्रस्ट\r\nकरते हैं। आंख मूंद कर करके ट्रस्ट करते हैं। जिनका लग्नेश अच्छा होता है। वो\r\nअच्छे चरित्रवान होते हैं। उनका वो व्यवहार कुशल भी होते हैं। उनका स्वभाव भी अच्छा होता है और रियल में उनके अंदर\r\nपरमात्मा कुछ ऐसे गुण देता है जो उनको चरित्रवान बनाता है। चरित्रवान के\r\nक्या-क्या गुण होते हैं कभी इस पर भी हम लोग वीडियो बनाएंगे। फिर आता है बुद्धि।\r\nजी हां बुद्धि परमात्मा ने लगभग लगभग इस संसार में हर किसी को देकर के भेजी है।\r\nबहुत कम लोग होते हैं जो थोड़ा इससे इसके दुष्प्रभाव में आ जाते हैं। मतलब बुद्धि\r\nसे बहुत ज्यादा कमजोर हो जाते हैं या जिनके पास बुद्धि नहीं होती। पर मैक्सिमम लोगों के पास बुद्धि होती है। पर फिर भी\r\nबुद्धिमान होते हुए भी लोग अपने जीवन में\r\nसफलता हासिल नहीं कर पाते। लोग अपने संबंधों को अच्छा बनाकर नहीं रख सकते। लोग\r\nजो हैं बुद्धिमान होते हुए भी अपने स्वास्थ्य की रक्षा नहीं कर पाते। बहुत\r\nसारे एस्पेक्ट है बुद्धि के। कहते हैं ना कि बुद्धिमान जो व्यक्ति होता है वह जीवन\r\nमें किसी भी विषम परिस्थितियों में रह के भी बड़े आराम से उन विषम परिस्थितियों से\r\nबाहर निकलने में कामयाब हो जाता है। हां, बुद्धि की बहुतेंस है। यह मुझे समझाने की\r\nआवश्यकता ही नहीं। आप सभी लोग समझते हैं। फिर उत्तम स्वास्थ्य यह भी लग्नेश ही देता\r\nहै। जिन लोगों का लग्नेश कमजोर होता है, उनको जीवन में बार-बार बीमारियां घेर लेती\r\nहैं। छोटी-छोटी प्रॉब्लम भी बड़ी समस्या बन जाती है। कभी-कभी तो बचपन से ही उनको\r\nबीमारियों का सामना करना पड़ जाता है। तो हेल्थ, ओवरऑल हेल्थ यह भी एक बड़ा\r\nमहत्वपूर्ण पड़ाव है। फिर है सोच और आत्मविश्वास। जी हां, कॉन्फिडेंस। बड़ी\r\nसोच यह भी लगन की ही देन है। हो रही ना\r\nबड़ी हैरानी। अच्छा कई बार हम बड़े कंफ्यूज होते हैं और ये देख के कि हर आदमी\r\nसोचता तो अच्छा ही है अपनी तरफ से पर फिर भी उसको सफलता नहीं मिलती। एक होता है\r\nख्वाब सपने और एक होती है सोच। दोनों में अंतर होता है। आप किसी से पूछेंगे आप अमीर\r\nबनना चाहते हो? वो कहेगा यस मैं अमीर बनना चाहता हूं। उसका ख्वाब हो सकता है। पर\r\nक्या उसकी सोच है? जिस व्यक्ति की सोच अमीर बनेगी बनने की है, वो उसका रास्ता\r\nअपने आप खोज ही लेगा। जिस व्यक्ति की सोच हेल्दी बनने की है, वह हेल्दी बन रहने के\r\nउपाय खोज ही लेगा। जिस व्यक्ति की सोच संबंधों को अच्छा बनाए रखने की है वो उसके\r\nरास्ते खोज ही लेगा। जी हां, ये ध्यान रखिएगा सोच पर पूरी लाइफ निर्भर करती है।\r\nआपने पुस्तक पढ़ी भी होगी बड़ी सोच का बड़ा जादू कि बड़ा सोचो।\r\nबहुत सारी बुक्स हैं मार्केट में। आप उनको पढ़ सकते हैं और समझ सकते हैं। परंतु\r\nहमारे ऋषियों ने तो उसको लगन के माध्यम से पहले ही समझा दिया कि मनुष्य जीवन में अगर\r\nहमें जीवन में तरक्की उन्नति करनी है और अच्छी तरह से जीवन को जीना है तो अच्छी\r\nसोच होना बहुत जरूरी है। आत्मविश्वास के\r\nबिना तो सब कहानी फेल है। आपको बहुत अच्छी चीजें आती हैं। आपको बहुत अच्छी नॉलेज है।\r\nपर उस नॉलेज को आप एक्सप्लेन नहीं कर सकते। चार लोगों को समझा नहीं सकते। और\r\nअचानक से कुछ नए और अजीब लोगों को देख के अजनबी लोगों को देख के आप अपनी बात को कह\r\nनहीं पाते हो। आप अचानक से कॉन्फिडेंस लूज कर जाते हो। जी हां, कॉन्फिडेंस लूज हो\r\nरहा है तो पक्का आपके लगन में कुछ गड़बड़ी है। वो आज आपको पता चल जाएगा। वह गड़बड़ी\r\nकैसे पता करते हैं और हो गई है तो चिंता मत कीजिएगा। आज के इस वीडियो में हम यह भी\r\nबताएंगे इसको कैसे ठीक किया जाता है। फिर आता है व्यक्तित्व वही वाली बात जिस पर हम\r\nचर्चा कर चुके हैं। पहला प्रभाव फर्स्ट अपीरेंस फर्स्ट इंप्रेशन क्या रहता है\r\nइंसान का और फिर है पूरी कुंडली की दिशा। यही मैं बार-बार आप लोगों को कह रहा हूं।\r\nपूरी कुंडली की डायरेक्शन सेट करने की ताकत। केवल अकेले लग्न के पास होती है। अगर\r\nलग्नेश बिगड़ गया तो यह बहुत बड़ी प्रॉब्लम में\r\nडाल देता है। लग्नेश अच्छा हो गया। इंसान\r\nमुसीबतों में, परेशानियों में, बुद्धि का उपयोग करते हुए शांति पूर्वक संयम से\r\nईश्वर की शरण में जाकर के अपने समय को निकाल लेता है और अच्छा समय आने पर जीवन\r\nमें तरक्की उन्नति भी करता है। पर प्रश्न उठता है कि कुछ विद्यार्थी कहेंगे या कुछ\r\nलोग कहेंगे कि पंडित जी हमें नहीं मालूम कि हमारा लग्न कौन सा है। बहुत आसान है\r\nलगन पता लगाना। आपने देखना है ये कुंडली का पहला भाव है जिसे हम बार-बार लिख रहे\r\nहैं कि यह लग्न है। जी हां, आपने देखना है यहां पर कोई ना कोई संख्या लिखी होती है।\r\nएक नंबर से लेकर के 12 नंबर तक। एक से ले 12 तक कोई ना कोई आपको संख्या लिखी\r\nमिलेगी। अगर मान लीजिए कि यहां दो नंबर लिखा है तो दो नंबर पर आपको देखना है कि\r\nकौन सी राशि आती है। आज ज्योतिष में 12 राशियां होती हैं। तो यहां पर देखेंगे दो\r\nनंबर लिखा है इसका मतलब वृष है। ये वृष तो हम कहेंगे ये वृष लग्न की कुंडली है। ऐसे\r\nकिसी का अगर एक लिखा होगा तो मेष लग्न की कुंडली हो जाएगी। दो लिखा होगा नंबर तो\r\nवृष लग्न की कुंडली हो जाएगी। अगर यहीं पर नंबर तीन लिखा हो तो मिथुन लग्न हो जाएगा।\r\nचार लिखा हो तो कर्क लग्न हो जाएगा। पांच लिखा हो तो सिंह लग्न हो जाएगा। छह लिखा\r\nहो तो कन्या लग्न हो जाएगा। सात लिखा हो तो\r\nतुला हो जाएगा। आठ लिखा हो तो वृश्चिक हो जाएगा। नौ लिखा हो तो धनु हो जाएगा और 10\r\nलिखा हो तो मकर हो जाएगा और 11 लिखा हो तो कुंभ हो जाएगा और 12 लिखा हो तो मीन हो\r\nजाएगा। ये शायद दिखाई नहीं दे रहा। आप यहां से देख लीजिए। मीन\r\nयानी कि यहां पर 12 नंबर लिखा है तो आपकी कुंडली मीन लग्न की है। अब इसी प्रकार से\r\nजो भी आपका लग्न आता है उसका लग्नेश यानी कि लग्न का स्वामी जो यहां पर राशि है उस\r\nराशि का स्वामी ग्रह कौन सा है? यह हमें देखना है। अगर मेष राशि है यानी नंबर एक\r\nकी राशि है तो मंगल हो जाएगा लग्नेश। नंबर\r\nदो की राशि है तो शुक्र हो जाएगा आपका लग्नेश।\r\nनंबर तीन है तो बुध हो जाएगा लग्नेश। नंबर चार है तो\r\nचंद्रमा हो जाएगा लग्नेश। नंबर पांच है तो सूरज हो जाएगा लग्नेश। नंबर छह है तो बुध\r\nहो जाएगा। नंबर सात है शुक्र हो जाएगा। नंबर आठ है मंगल हो जाएगा। नंबर नौ है तो\r\nबृहस्पति। नंबर 10 है तो शनि। नंबर 11 है\r\nतो भी शनि और नंबर 12 है तो बृहस्पति। याद रखने का यह गुरु हो जाता है। यहां तक आपको\r\nपता चला कि लग्न कैसे देखते हैं, लग्न का स्वामी कैसे देखते हैं यानी कि लग्नेश\r\nकैसे देखते हैं? यह आप आराम से नोट भी कर सकते हो। और मैं हमारी टीम को बोलूंगा कि\r\nवो हमारे डिस्क्रिप्शन बॉक्स में भी डाल दे। वहां से जाकर के भी आप देख सकते हो। अच्छा डिस्क्रिप्शन बॉक्स चेक करते हो कि\r\nनहीं करते हो आप? आप जरूर चेक करा करो। हमारी टीम बहुत मेहनत कर रही है आजकल। उस\r\nपर बहुत सारा कंटेंट भी लिखती है जो आप वीडियो में देखते हैं उसके शॉर्ट फॉर्म\r\nमें वहां पर भी लिखा होता है। उसको जरूर डिस्क्रिप्शन बॉक्स को जाकर देखा करो। अब अगले स्टेप पर आते हैं कि ये जो लग्नेश है\r\nये आपकी जन्म पत्रिका में कहां पर विराजमान है? तो हमारे जन्म पत्रिका में\r\nकेंद्र होता है एक चार सात और 10। जी हां ये केंद्र स्थान\r\nएक होता है त्रिकोण एक 4 10 तो हो गए केंद्र और फिर आता है\r\nत्रिकोण त्रिकोण होता है 1 5 9 जी हां 1 5 9 जी\r\nहां ये पांचवा भाव है और ये नौवा भाव है।\r\n1 5 9 इसको चलो ऐसे बना देते हैं हम। इसको\r\nत्रिकोण कहते हैं। यह ट्रायंगल बन गया। फर्स्ट 5 न इसको समझ लीजिए। अब समझने वाली\r\nबात क्या है? आपने यह देखना है आपकी कुंडली में लग्न का स्वामी यानी कि लग्नेश\r\nकेंद्र में बैठा है या त्रिकोण में बैठा है। जी हां। अगर वह लगश केंद्र में बैठा\r\nहै। एक चार सात 10 इन स्थानों में बैठा है\r\nतो आपको खुश होने की आवश्यकता है। बलवान है पर अभी जो है निर्णय तक मत पहुंचिए।\r\nज्योतिष में बहुत सारे स्टेप्स आते हैं। ज्योतिष परमटेशन और कॉम्बिनेशंस का खेल\r\nहै। बहुत सारे स्टेप्स आते हैं। तो पर पहला स्टेप यही है कि अब यह समझना है\r\nजिसका भी लग्नेश एक चार 7 10 भाव में है। बलवान है। अभी के\r\nलिए बलवान है। आगे देखते हैं उसका क्या होता है। दूसरा\r\nयदि 1 5 9 1 5 और नौ में\r\nकिसी का लग्नेश बैठा है। बहुत शुभ है। बहुत अच्छा है। यह कई गुण दे देता है\r\nइंसान के अंदर। पर लग्नेश को भी अच्छा बनाता है। कहने का मतलब इन जगहों पर बैठना\r\nअच्छा माना जाता है लग्नेश का। कौन से ऐसे स्थान है जहां पर लग्नेश का बैठना बहुत\r\nअच्छा नहीं माना जाता। वो कौन से? दुख स्थान। कुंडली का छठा भाव, आठवां भाव,\r\n12वा भाव। जी हां, छ आठ और 12 ये भाव यानी\r\nकि कुंडली का छठा भाव, आठवां भाव और 12वा\r\nभाव। जी छ 8 12 इन भावों में अगर लग्नेश\r\nचला जाए तो उसको अच्छा नहीं माना जाता। पर अभी भी निर्णय पे ना पहुंचो। मैंने कहा ना\r\nअभी कई स्टेप आएंगे। कभी-कभी ऐसा भी होता है इन भाव में बैठकर के भी ग्रह बलवान हो\r\nजाता है। पर कभी-कभी होता है। अक्सर वो आगे ज्योतिष के जब सूत्र आते हैं जब हम\r\nपूरा ज्योतिष शास्त्र सीखते हैं तो इस चीज का भी ज्ञान हमें अच्छे से हो जाता है। पर\r\nहमें और क्या समझना है? अभी कुछ और भाव रह गए। कुंडली में दूसरा भाव रह गया। कुंडली\r\nमें तीसरा भाव रह गया। कुंडली में 11वा भाव रह गया।\r\nइन भाव में अगर बैठ जाए जैसे लग्नेश सेकंड हाउस में बैठ जाए। यह बहुत बलवान भी नहीं\r\nहोता, बहुत शुभ भी नहीं होता। बट ये खराब भी नहीं होता। इसको आप यह कह सकते हो कि\r\nना यह अच्छा है ना यह खराब है। पर लग्नेश अगर तीसरे में बैठ जाए\r\nइसके कुछ पॉजिटिव पॉइंट्स रहते हैं। कुछ नेगेटिव पॉइंट्स रहते हैं। जैसे तीसरा भाव\r\nमेहनत मशक्कत का है। ये इंसान के जीवन में मेहनत मशक्कत बहुत बढ़ा देता है। स्ट्रगल\r\nबहुत कराता है। बहुत हार्ड वर्क करना पड़ता है। हां, अगर किसी का लग्नेश तीसरे\r\nमें उन्हें बहुत ज़्यादा हार्ड वर्क करना ही चाहिए। क्योंकि भगवान चाहता है आपसे कि आप ज़्यादा हार्ड वर्क को तो उनको सफलता\r\nमिलती है तो उनको फायदा होता है। इसी प्रकार से अगर लग्नेश 11व भाव में बैठ\r\nजाए। कुछ विद्वान मानते हैं बहुत अच्छी बात है। क्योंकि 11वा भाव लाभ भाव होता है। पर कुछ\r\nकहते हैं नहीं भाई यह पाप भाव भी होता है। है ना? तो पाप भाव में अगर बैठेगा तो ये\r\nकुछ गड़बड़ियां भी करता है। दोनों ही बातें ठीक है। कभी-कभी ज्योतिष में दोनों ही बातें ठीक होती है कि लाभ भी होता है\r\nऔर जीवन में कुछ समस्याएं भी आती हैं। तो आपने देखा कि ग्रहों की प्लेसमेंट यानी\r\nलग्नेश की प्लेसमेंट कैसे चेक की जाती है। आपने देखा कि आपका\r\nलग्नेश कौन से भाव में बैठा है। उसके अनुसार आपने निर्णय किया। पर अब एक स्टेप\r\nऔर आगे चलेंगे। वो क्या स्टेप है? जो आपका लग्नेश है जो आपका लग्नेश है\r\nउसे देखिए कि वो D9 में कहां पर प्लेस्ड है। मान लीजिए ये D9 चार्ट है।\r\nआज आप सीख ही जाएंगे पूरा हैं। ज्योतिष में कैसे देखते हैं। D9 चार्ट यानी कि\r\nनवमश कुंडली। जब आप अपनी कुंडली खोलेंगे ना सॉफ्टवेयर में जहां पर लग्न कुंडली\r\nहोती है उसके साथ में यह कुंडली लिखी होती है जिसे नवमश कुंडली लिखा होता है हिंदी में इंग्लिश में उसे डीाइन चार्ट कह देते\r\nहैं। तो आपको यह देखना है कि इस लग्नेश जो निकल के आया था मेन चार्ट मेन चार्ट को डी\r\nवन चार्ट भी बोल देते हैं। यह D1 चार्ट का लग्नेश\r\nका लग्नेश यह देखो कि ये D9 में कैसे बैठा है। वही फार्मूला\r\nकेंद्र केंद्र\r\nकेंद्र केंद्र या त्रिकोण\r\nअच्छा, कमाल की बात। पहला जो भाव होता है ना, यह केंद्र भी होता है और यह त्रिकोण\r\nभी होता है। है ना मज़ेदार बात? इसीलिए तो इसको कहा जाता है कि यह सिंहासन है कुंडली\r\nका राजा है ये। केंद्र भी है, त्रिकोण भी है, सर्वशक्तिशाली होता है। अगर लग्नेश\r\nकेंद्र में बैठ जाए नवमश कुंडली में तो\r\nबहुत अच्छा है। त्रिकोण में बैठ जाए तो और भी अच्छा है। पर कुंडली के इन दुख स्थानों\r\nमें छ 8 12 भाव में बैठे उसे अच्छा नहीं\r\nमाना जाता। आपको यदि आज इस वीडियो में ना समझ लगे कि\r\nकेंद्र क्या होता है? त्रिकोण क्या होता है? तो एस्ट्रो पाठशाला YouTube चैनल में\r\nहमने केंद्र का और त्रिकोण का अलग-अलग वीडियो बना रखा है और हमारी क्लासेस भी\r\nचलती हैं। जो हमारी क्लासेस हैं उसमें हमने बड़ा डिटेल में बताया है कि आपको\r\nकेंद्र क्या है और त्रिकोण क्या है। तो ज्योतिष में नियम कहता है अगर लग्न का\r\nस्वामी लग्नेश त्रिकोण में वेल प्लेस्ड होगा।\r\nसौग्रही या उच्च का होगा उस पर भी बात करेंगे तो लग्नेश आपका बलवान है। जी हां।\r\nअब यहां पर एक प्रश्न उठता है कि अगर ग्रह\r\nसग्रही हो जाए। सग्रही का मतलब होता है\r\nअपनी ही राशि में या उच्च का हो जाए ग्रह\r\nतो उच्च के ग्रह को बहुत अच्छा माना जाता है। उसके विपरीत नीच राशि का ग्रह शत्रु\r\nराशि में बैठा हुआ ग्रह अच्छे नहीं माने जाते। परंतु जो ग्रह अपनी ही राशि में\r\nबैठा हो, उच्च का बैठा हो या मूल त्रिकोण राशि में बैठा हो, मूल त्रिकोण राशि में\r\nबैठा हो तो भी बलवान हो जाता है। अच्छा ये टर्म अगर आपको ना समझ में आए ना मूल\r\nत्रिकोण राशि क्या होती है? उच्च का ग्रह क्या होता है? नीच का ग्रह क्या होता है?\r\nतो बिल्कुल चिंता ना करें। एस्ट्रो पाठशाला में हर टॉपिक कवर किया हुआ है।\r\nआपको बस पीछे जाना है। चैनल में काफी पीछे तक जाना है क्योंकि हमारा एक्सपीरियंस है\r\n20 वर्ष से ज्यादा हो गए ज्योतिष सिखाते हुए तो बेताशा वीडियो हैं बहुत सारे आप\r\nवहां पे जाकर के भी जो है जाकर के चेक कर सकते हैं और फिर भी कोई दिक्कत आती है तो\r\nहमारे जो रेगुलर कोर्सेज चलते रहते हैं। आप उन रेगुलर कोर्सेज में भी हमसे\r\nडायरेक्ट मतलब लाइव कोर्स में पढ़ सकते हो आप। अच्छा कुछ लोग कहते हैं कि हमारे पास\r\nसमय का भाव रहता है कि गुरु जी आप जिस समय आप क्लास लेते हैं उस समय हम बिजी होते\r\nहैं। किसी काम में फंसे हुए होते हैं तो क्या करें? तो उनके लिए हमारी ऐप भी है।\r\nहमारी ऐप का नाम भी एस्ट्रो पाठशाला ऐप है। आप उस ऐप पे जाकर के भी हमारे\r\nरिकॉर्डेड वीडियो कोर्सेज को भी ज्वाइन कर सकते हो। आप वहां से भी ज्योतिष सीख सकते\r\nहो। और हां ध्यान रखिएगा हर संडे 11:00 बजे हमारा लाइव ऑनलाइन डाउट क्लियर सेशन\r\nचलता है। वहां पर कोई विद्यार्थी पामिस्ट्री से रिलेटेड एस्ट्रोलॉजी से\r\nरिलेटेड, लाल किताब से रिलेटेड, जैेमिनी ज्योतिष से रिलेटेड जो उसका जो मन करता है\r\nवो अपना प्रश्न पूछता है। मंत्र से रिलेटेड, तंत्र से रिलेटेड और दान पुण्य से रिलेटेड जो उसका मन करता है वो प्रश्न\r\nपूछता है और यह यह वीडियो भी आपको YouTube पर मिल जाएंगे हमारे चैनल में एस्ट्रो\r\nपाठशाला में और वैसे ही अगर कोई वीडियो आपका आपको एस्ट्रो पाठशाला चैनल पे ना\r\nमिले तो मेरे नाम का भी एक चैनल है सुनील वशिष्ठ। आप उस चैनल पे भी जाकर देखिए।\r\nवैसे तो मुख्य रूप से हमारे तीन चैनल मेन है। एस्ट्रो पाठशाला है और सुनील वशिष्ठ\r\nके नाम से है और एकदा सोल पाथ इस चैनल को जरूर देखिए। इसमें बहुत अच्छे-अच्छे\r\nनक्षत्रों के ऊपर और बहुत अच्छे-अच्छे वीडियो डले हुए हैं। आप यहां पर भी जाकर के देख सकते हैं। तो हम बात कर रहे थे कि\r\nअगर ग्रह आपका सग्रही है, उच्च का है, मूल\r\nत्रिकोण राशि में बैठा है, केंद्र में बैठा है, त्रिकोण में बैठा है। और D1\r\nचार्ट D1 चार्ट में इन स्थिति में बैठा हुआ है। और सेम सेम का मतलब है D9 चार्ट\r\nमें भी वह सौग्रही या उच्च का या इनमें बैठा हुआ है और केंद्र त्रिकोण में बैठा\r\nहुआ है। बहुत बलवान हो जाता है। बहुत ताकतवर हो जाता है यह लग्नेश और लग्नेश का\r\nबल सर्वोपरि है। बहुत अच्छा माना जाता है ज्योतिष में इसको। अब हमें और क्या समझना\r\nहै? चलिए आगे बढ़ते हैं। अगर यहां पर मैंने आपको बताया था लग्ने 6 8 12 में बैठ\r\nजाए तो अच्छी बात नहीं मानी जाती है। अब एक\r\nसूत्र समझ लो। बेशक डी1 चार्ट यानी कि\r\nलग्न कुंडली में आपका कोई ग्रह ताकतवर बैठा हुआ है। पर नवमश कुंडली में\r\nयानी कि डी न चार्ट में अगर वही ग्रह छठे आठव भाव में चला जाए\r\nतो कमजोर हो जाएगा और कमजोर ही माना जाएगा। हां कि यह मत सोचना कि डी वन चार्ट\r\nमें मेन चार्ट में तो बहुत कुंडली में बहुत अच्छा है। ऐसे लोग बहुत आते हैं कंफ्यूज हो के बेचारे हमारे पास। कहते\r\nआचार्य जी देखना हमारा सूर्य उच्च का है। हम बचपन में थे तो सब कहते थे चार ग्रह\r\nउच्च के हैं। आपके तो आपके तो ग्रह बहुत बलवान है। आप तो अमीर बनोगे। आपका तो\r\nराजयोग बना हुआ है। एक्चुअली में वो बेचारों का कसूर नहीं। वो नवमश कुंडली तक\r\nनहीं पहुंचते या नवमाश कुंडली का विश्लेषण ढंग से नहीं करते। अगर नवमश कुंडली का ढंग\r\nसे विश्लेषण करें तो वो उनको उनका आंसर मिल जाएगा। वहीं की वहीं पर आंसर मिल\r\nजाएगा। तो उन्हें मालूम लग जाएगा कि यार नवमश में कुछ गड़बड़ हो गई है। कभी-कभी\r\nग्रह जो है नवमश में बेचारा पिट जाता है। कमजोर हो जाता है तो वो भी बात अच्छी नहीं\r\nमानी जाती। तो व्यक्ति को लक्षण जो आते हैं वो कमजोरी के ही आएंगे। मतलब जो जो\r\nनुकसान हो सकते हैं लग्नेश के कमजोर होने से वो सब परिणाम भुगतने पड़ जाते हैं। तो\r\nआपने यह सब चीजें देखी। एक चीज और आपको मैं अच्छे से बता दूं कि लग्न के बारे में\r\nजी हां लगन को देखने का एक तरीका यह भी है। इसको मैं कई बार कहता हूं यह सीक्रेट\r\nफार्मूला। अगर हमें जल्दबाजी में देखना हो कुंडली का\r\nलग्नेश कैसा लगन कैसा है? लग्न कैसा है यह देखने\r\nके लिए एक बेहतरीन फार्मूला है कि आपको कुंडली में देखना है कि गुरु ग्रह कैसा है\r\nऔर मरकरी कैसा है। यानी कि बुध ग्रह\r\nऔर गुरु ग्रह। जी हां, यह दो ग्रह आपकी कुंडली में कैसे बैठे? अगर यह दो ग्रह\r\nकुंडली में बलवान हो जाए, तो आपका लगन बलवान है। फिर से मैं रिपीट\r\nकर रहा हूं। यह दो ग्रह किसी की जन्म पत्रिका में बुध और गुरु अगर बलवान हो जाए\r\nजो लग्नेश के कमजोर होने से नुकसान होने थे वो नहीं होते हैं क्योंकि आप में से\r\nबहुत सारे लोगों को टेंशन हो गई होगी कि यार मेरी भी कुंडली में लगने छठे में चला\r\nगया आठवें में चला गया 12व में चला गया अब मैं क्या करूं या तीसरे में आ गया दूसरे\r\nमें आ गया तो मैं क्या करूं चिंता चिंता मत कीजिए। अभी ऑप्शन है आपके पास। कुंडली\r\nमें चेक कीजिए कि गुरु और बुध कैसे बैठे हुए हैं। अगर गुरु और बुध आपकी कुंडली का\r\nजब आप अध्ययन करते हैं, विश्लेषण करते हैं। अगर यह दो ग्रह बलवान हैं। कोई फर्क\r\nनहीं पड़ता। आपका लग्नेश छठे चला गया, आठवें चला गया, 12व चला गया, उसका कोई\r\nसाइड इफेक्ट आपको देखने को नहीं मिलेगा। आपको लग्नेश इंटेलिजेंट ही बनाएगा। लगन से\r\nबुद्धि देखी जाती है। लग्नेश बुद्धि का इंप्लीमेंटेशन\r\nबुद्धि का इंप्लीमेंटेशन लग्नेश से देखा जाता है। जब लग्नेश 12व में चला जाता है\r\nतो कहते हैं इंटेलिजेंट तो होते हैं पर बुद्धि का इंप्लीमेंटेशन बहुत सही तरीके से नहीं कर पाते हैं। पर अगर गुरु और बुध\r\nजैसे दो ग्रह अच्छे हो जाए तो इंप्लीमेंटेशन भी बहुत अच्छा सा कर लेते\r\nहैं। इसलिए बहुत अह आपको ऐसे डॉक्टर मिल जाएंगे जिनका लग्ने 6 8 12 बैठा मिलेगा या\r\nबड़े अच्छे वकील मिल जाएंगे आपको। बड़े अच्छे कमाते धमाते लोग मिल जाएंगे आपको। जरूर देखना कि बुध और गुरु बलि मिलेंगे\r\nआपको। D1 D9 दोनों में देखना। और एक और चीज का कंफ्यूजन मैं यहां पर दूर कर दूं।\r\nकुछ नियम और भी लगते हैं। जैसे कि मंगल ग्रह छठे भाव में शनि\r\nआठव में और शुक्र 12व में\r\nयह ठीक माने जाते हैं। मतलब इन्हें खराब नहीं माना जाता। अब मान लीजिए आप मेष लग्न\r\nके जातक हैं। मेष यानी कि आप का लग्न में यहां नंबर एक लिखा हुआ है। उसका स्वामी\r\nहोता है मंगल। अब वो आ गया छठे भाव में। तो उस नियम से जो आज हम बता रहे हैं कि तो\r\nगड़बड़ हो गई। पर ऐसा हुआ नहीं क्योंकि मंगल छठे में इतना गड़बड़ होता नहीं है तो\r\nऐसे लोगों को भी परेशानी नहीं होती। ध्यान रखिए ज्योतिष में बहुत सारे नियम काम करते\r\nहैं। और हां जो लोग ज्योतिष सीखना चाहते\r\nहैं उन्हें धैर्य पूर्वक इन सभी फार्मूलों को सीखना चाहिए। आधा\r\nअधूरा ज्ञान लेकर के ना दौड़ लगाएं। हर चीज को स्टेप बाय स्टेप आपको सीखना है। हो\r\nसकता है बहुत जो बारीक फार्मूले हैं, बारीक जो सिद्धांत हैं वो हम सब के सब\r\nपूरा का पूरा एक्सप्लेन ना कर पाए हो। इसलिए हम टुकड़े पे बना बना करके वीडियो हम डालते रहते हैं। तो आप बोलोगे तो हम वो\r\nभी बड़ा डिटेल में भी करेंगे उसके बारे में। तो पर मोटा मोटी लग्नेश आपका कमजोर\r\nहै कि बलवान है आपको आईडिया लग जाएगा। मोटा-मोटा तो आपको आईडिया लग जाएगा। इस वीडियो से ही लग जाएगा कि अगर आपको इस तरह\r\nकी सिचुएशनंस बनती हुई दिखाई देती हैं तो लग्नेश बलवान है। लग्नेश कमजोर होने से\r\nक्या प्रॉब्लम चलती है? लग्नेश कमजोर होने से व्यक्ति का स्वास्थ्य ठीक नहीं रहता।\r\nव्यक्ति की सोच कमजोर रहती है। व्यक्ति किसी के भी इंप्रेशन में बहुत जल्दी आ\r\nजाता है। व्यक्ति बहुत ज्यादा सोच विचार करके कार्य नहीं करता। व्यक्ति की कोई\r\nप्लानिंग कोई बड़ी लंबी प्लानिंग ऐसी कुछ होती नहीं है। ख्वाबों की दुनिया में ज्यादा रखता है। प्रैक्टिकल लाइफ से सोच\r\nनहीं पाता। जब लग्नेश कमजोर होता है तो राशि स्वामी यानी चंद्रमा। चंद्रमा होता\r\nहै मन। तो व्यक्ति मन के अधीन हो जाता है और जो उसका मन कहता है वह करने लग जाता\r\nहै। वैसे तो एक फिलोसफी यह भी है कि मन जैसा कहता है वैसे ही करना चाहिए। पर पूरी\r\nतरह ठीक नहीं है। ये बुद्धि का उपयोग जरूर करना चाहिए। क्योंकि बुद्धि कहां है?\r\nबुद्धि तो यहीं पर है। पहले भाव में कहते हैं ना जोश में होश की आवश्यकता चाहिए। बुद्धि का\r\nप्रयोग जरूर होना चाहिए। मन कुछ भी कहे मन जितना मर्जी कुछ भी समझा रहा है आपको पर\r\nबुद्धि से विश्लेषण करना बहुत जरूरी है कि यह हमारे लिए कहीं गलत तो नहीं हो जाएगा\r\nयह फैसला कोई भी डिसीजन लाइफ में आप लेने जा रहे हैं बुद्धि का उपयोग जरूर करें तो\r\nउससे में लग्न की आपकोेंस का पता चलेगा धन्यवाद"}];
